window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cslb-law"] = window.COURSE_LANG["cslb-law"] || {};
window.COURSE_LANG["cslb-law"]["es"] = [
  {"id":1,"q":"En California, generalmente se requiere una licencia de contratista cuando el costo combinado de mano de obra y materiales en un proyecto es de al menos:","opts":["$200","$500","$1,000","$2,500"],"re":"Desde la AB 2622 (vigente el 1 de enero de 2025), la exención de 'trabajo menor' cubre trabajos de menos de $1,000 que no requieren permiso de construcción ni usan empleados; a partir de $1,000 se requiere licencia. (Aumentado desde $500; el trabajo no se puede dividir para evadir el límite.) Fuente: B&P Code §7048."},
  {"id":2,"q":"La edad mínima para solicitar una licencia de contratista en California es:","opts":["16","18","21","25"],"re":"Los solicitantes deben tener al menos 18 años de edad."},
  {"id":3,"q":"La fianza de contratista exigida a la mayoría de los licenciatarios activos de California es por el monto de:","opts":["$12,500","$15,000","$25,000","$100,000"],"re":"La fianza de contratista es de $25,000 (aumentada desde $15,000 con vigencia a partir del 1 de enero de 2023)."},
  {"id":4,"q":"¿Con qué frecuencia debe renovarse una licencia de contratista de California?","opts":["Cada año","Cada 2 años","Cada 3 años","Cada 5 años"],"re":"Las licencias activas e inactivas se renuevan cada dos años."},
  {"id":5,"q":"Un licenciatario debe notificar a la CSLB un cambio de domicilio comercial dentro de:","opts":["10 días","30 días","90 días","6 meses"],"re":"Los cambios de domicilio deben reportarse al Board dentro de 90 días."},
  {"id":6,"q":"La persona que toma y aprueba los exámenes de oficio y de leyes para calificar una licencia es el:","opts":["Agente registrado","Individuo calificador","Garante de la fianza","Empleado responsable"],"re":"El individuo calificador — un RMO (Responsible Managing Officer, un propietario) o RME (Responsible Managing Employee, un empleado) — posee el conocimiento del oficio que califica la licencia."},
  {"id":7,"q":"Un RME (Responsible Managing Employee) debe estar empleado por el licenciatario al menos:","opts":["8 horas/semana","32 horas/semana o el 80% de las horas del negocio","16 horas/semana","Solo tiempo completo"],"re":"Un RME (el empleado calificador) debe ser un empleado de buena fe (bona fide) activamente ocupado al menos 32 horas O el 80% del total de horas por semana que opera el negocio, lo que sea menor. Fuente: CCR Title 16, Div. 8, §823(a)."},
  {"id":8,"q":"¿Qué forma de negocio hace que los propietarios sean personalmente responsables de todas las deudas del negocio?","opts":["Corporación","Compañía de responsabilidad limitada","Propietario único (sole proprietorship)","Sociedad limitada (socios limitados)"],"re":"Un propietario único es personalmente responsable de todas las deudas y obligaciones del negocio."},
  {"id":9,"q":"Generalmente se requiere una 'Bond of Qualifying Individual' (fianza del individuo calificador) cuando el calificador es:","opts":["Un propietario único","Un RMO que posee el 10% o más de la corporación","Un RME o un RMO que posee menos del 10%","Cualquier calificador, siempre"],"re":"La fianza del calificador ($25,000) se requiere para un RME, o un RMO que posee menos del 10% de las acciones con derecho a voto."},
  {"id":10,"q":"Contratar sin licencia cuando se requiere una es generalmente un(a):","opts":["Infracción sin penalización","Delito menor (misdemeanor)","Delito grave (felony) en la primera ofensa","Asunto civil únicamente"],"re":"Contratar sin licencia es un delito menor; las penalizaciones aumentan en ofensas repetidas."},
  {"id":11,"q":"Un contratista sin licencia que demanda para cobrar el pago de un trabajo que requería licencia generalmente:","opts":["Gana el pago completo","Recupera solo el costo de materiales","Queda impedido de cobrar y podría tener que reembolsar los montos pagados","Recupera el 50%"],"re":"El B&P Code §7031 impide que los contratistas sin licencia demanden por compensación y permite a los clientes recuperar lo que ya pagaron."},
  {"id":12,"q":"Cuando el individuo calificador se desvincula de una licencia, el licenciatario debe notificar a la CSLB dentro de:","opts":["10 días","30 días","90 días","1 año"],"re":"La desvinculación del calificador debe reportarse dentro de 90 días, o la licencia puede ser suspendida."},
  {"id":13,"q":"Una licencia de joint venture (empresa conjunta):","opts":["No necesita registro por separado","Combina dos o más licenciatarios y debe estar licenciada por sí misma","Es solo para obras públicas","Reemplaza la licencia individual de cada socio"],"re":"Un joint venture de contratistas licenciados debe obtener su propio número de licencia de joint venture."},
  {"id":14,"q":"En una ecuación contable básica, los Activos son iguales a:","opts":["Pasivos − Capital","Pasivos + Capital del propietario","Ingresos − Gastos","Capital − Pasivos"],"re":"Activos = Pasivos + Capital del propietario es la ecuación contable fundamental."},
  {"id":15,"q":"El dinero que se le debe AL negocio por parte de los clientes se registra como:","opts":["Cuentas por pagar","Cuentas por cobrar","Utilidades retenidas","Retiro del propietario"],"re":"Las cuentas por cobrar son el dinero que los clientes le deben al negocio."},
  {"id":16,"q":"El dinero que el negocio DEBE a los proveedores es:","opts":["Cuentas por cobrar","Cuentas por pagar","Utilidad bruta","Patrimonio neto"],"re":"Las cuentas por pagar son lo que el negocio les debe a otros."},
  {"id":17,"q":"La utilidad bruta se calcula como:","opts":["Ingresos − todos los gastos","Ingresos − costo de bienes vendidos","Activos − pasivos","Utilidad neta + impuestos"],"re":"Utilidad bruta = ingresos − costo de bienes vendidos, antes de gastos generales."},
  {"id":18,"q":"Los costos generales (overhead) se describen mejor como:","opts":["Mano de obra directa en un trabajo","Materiales para un trabajo específico","Costos continuos no ligados a un solo trabajo (renta, seguro, oficina)","Facturas de subcontratistas"],"re":"Los gastos generales son el costo indirecto de operar el negocio, no cargable a un solo trabajo."},
  {"id":19,"q":"Un margen (markup) del 25% sobre un costo de trabajo de $4,000 produce un precio de venta de:","opts":["$4,250","$4,500","$5,000","$5,333"],"re":"$4,000 × 1.25 = $5,000. (El margen es sobre el costo, no sobre el precio.)"},
  {"id":20,"q":"El método contable que registra los ingresos cuando se ganan y los gastos cuando se incurren (no cuando se mueve el efectivo) es:","opts":["Base de efectivo (cash basis)","Base de devengo (accrual basis)","Solo contrato completado","Caja chica"],"re":"La base de devengo registra ingresos/gastos cuando se ganan/incurren, sin importar el momento del efectivo."},
  {"id":21,"q":"Una 'razón corriente' (current ratio) mide la capacidad de una empresa para:","opts":["Crecer a largo plazo","Pagar obligaciones a corto plazo","Aumentar el margen","Reducir impuestos"],"re":"Razón corriente = activos corrientes ÷ pasivos corrientes; mide la liquidez a corto plazo."},
  {"id":22,"q":"La depreciación de una camioneta de trabajo es:","opts":["Un pago en efectivo cada año","Una asignación del costo de un activo a lo largo de su vida útil","Un tipo de seguro","Un pasivo"],"re":"La depreciación distribuye el costo de un activo de capital a lo largo de los años en que se utiliza."},
  {"id":23,"q":"El capital de trabajo es igual a:","opts":["Activos totales","Activos corrientes − pasivos corrientes","Ingresos − gastos generales","Capital + deuda"],"re":"Capital de trabajo = activos corrientes − pasivos corrientes."},
  {"id":24,"q":"¿Qué documento resume los ingresos y gastos durante un período para mostrar la ganancia o pérdida?","opts":["Balance general","Estado de resultados (pérdidas y ganancias)","Programa de fianzas","Renuncia de gravamen"],"re":"El estado de resultados (P&L) muestra los ingresos, gastos y la ganancia/pérdida resultante de un período."},
  {"id":25,"q":"El impuesto federal sobre la renta retenido de los cheques de pago de los empleados es:","opts":["Un gasto del empleador","Mantenido en fideicomiso y remitido al IRS","Opcional para empresas pequeñas","Reembolsado al empleador"],"re":"La retención es el dinero del empleado mantenido en fideicomiso por el empleador y pagado al IRS."},
  {"id":26,"q":"Los impuestos FICA financian:","opts":["Solo la incapacidad estatal","Social Security y Medicare","Solo el desempleo","La compensación de trabajadores"],"re":"FICA cubre Social Security y Medicare, repartido entre empleador y empleado."},
  {"id":27,"q":"Un problema de flujo de efectivo significa más directamente que el negocio:","opts":["No es rentable","Carece de efectivo para cumplir las obligaciones a su vencimiento","Tiene demasiados activos","Paga muy pocos impuestos"],"re":"Los problemas de flujo de efectivo son un problema de tiempo: no hay suficiente efectivo disponible cuando vencen las cuentas, aunque sea rentable."},
  {"id":28,"q":"El seguro de compensación de trabajadores de California se requiere cuando un negocio tiene:","opts":["10 o más empleados","5 o más empleados","Cualquier empleado","Solo empleados sindicalizados"],"re":"Cualquier empleador con aunque sea un empleado debe tener compensación de trabajadores."},
  {"id":29,"q":"Un licenciatario sin empleados puede presentar ante la CSLB un(a):","opts":["Fianza de cumplimiento (performance bond)","Certificado de exención de compensación de trabajadores","Liberación de gravamen","Aviso de finalización"],"re":"Un licenciatario sin empleados puede certificar una exención de la compensación de trabajadores."},
  {"id":30,"q":"En California, las horas extra diarias (1.5×) generalmente comienzan después de:","opts":["6 horas","8 horas","10 horas","12 horas"],"re":"Las horas extra a 1.5× comienzan después de 8 horas en un día (y después de 40 en una semana)."},
  {"id":31,"q":"El pago de doble tiempo (2×) en California generalmente se requiere después de:","opts":["8 horas/día","10 horas/día","12 horas/día","16 horas/día"],"re":"El doble tiempo aplica después de 12 horas en una jornada laboral (y después de 8 horas en el 7º día consecutivo)."},
  {"id":32,"q":"Un empleado que es despedido debe recibir su último cheque de pago:","opts":["Dentro de 72 horas","En el siguiente día de pago","Inmediatamente al momento del despido","Dentro de 30 días"],"re":"El salario final de un empleado despedido se debe inmediatamente al momento de la terminación."},
  {"id":33,"q":"A un empleado que renuncia sin aviso se le debe pagar el salario final dentro de:","opts":["Inmediatamente","24 horas","72 horas","El siguiente día de pago"],"re":"En caso de renuncia sin aviso, el salario final se debe dentro de 72 horas."},
  {"id":34,"q":"El formulario federal que se usa para verificar la elegibilidad de un nuevo empleado para trabajar es el:","opts":["W-2","W-4","I-9","1099"],"re":"El Formulario I-9 verifica la identidad y la autorización de trabajo de cada nuevo empleado."},
  {"id":35,"q":"¿Qué formulario completa un empleado para establecer la retención del impuesto sobre la renta?","opts":["I-9","W-4","W-2","1099-NEC"],"re":"El W-4 le indica al empleador cuánto impuesto sobre la renta debe retener."},
  {"id":36,"q":"Un trabajador pagado mediante el Formulario 1099-NEC generalmente se trata como un(a):","opts":["Empleado","Contratista independiente","Aprendiz","Socio"],"re":"Un 1099-NEC reporta pagos a un contratista independiente, no a un empleado."},
  {"id":37,"q":"La 'prueba ABC' de California (AB 5) se usa para determinar si un trabajador es:","opts":["Asegurable con fianza","Un empleado o un contratista independiente","Elegible para exención de horas extra","Un trabajador de obras públicas"],"re":"La prueba ABC presume que un trabajador es empleado a menos que se cumplan los tres elementos (A, B, C)."},
  {"id":38,"q":"Los nuevos empleados deben reportarse al New Employee Registry de la EDD dentro de:","opts":["20 días de la fecha de inicio del trabajo","60 días","90 días","Solo antes del primer cheque de pago"],"re":"Los empleadores reportan los nuevos empleados a la EDD dentro de 20 días."},
  {"id":39,"q":"El State Disability Insurance (SDI) en California es:","opts":["Pagado en su totalidad por el empleador","Deducido del salario del empleado","Lo mismo que la compensación de trabajadores","Opcional"],"re":"El SDI se financia mediante una deducción del salario del empleado, administrada por la EDD."},
  {"id":40,"q":"El seguro de desempleo federal y estatal (FUTA/SUI) generalmente es:","opts":["Retenido de los empleados","Un impuesto pagado por el empleador","Pagado por el cliente del contratista","No requerido en California"],"re":"El seguro de desempleo es un costo del empleador, no se retiene del salario de los trabajadores."},
  {"id":41,"q":"El descanso de comida requerido para un empleado no exento que trabaja más de 5 horas es de:","opts":["10 minutos","20 minutos","30 minutos sin goce de sueldo","60 minutos"],"re":"Se requiere un período de comida de 30 minutos sin goce de sueldo para turnos de más de 5 horas."},
  {"id":42,"q":"Generalmente se requiere un descanso pagado de 10 minutos por cada:","opts":["2 horas trabajadas","4 horas (o fracción mayor) trabajadas","6 horas trabajadas","8 horas trabajadas"],"re":"Se requieren descansos pagados de diez minutos por cada 4 horas (o fracción mayor) trabajadas."},
  {"id":43,"q":"Clasificar erróneamente a un empleado como contratista independiente puede resultar en:","opts":["Ninguna consecuencia","Impuestos atrasados, penalizaciones y responsabilidad","Un bono de la EDD","Mejora automática de licencia"],"re":"La clasificación errónea intencional expone al empleador a impuestos atrasados, penalizaciones y responsabilidad salarial."},
  {"id":44,"q":"La agencia que hace cumplir las leyes de salarios y horas de California es la:","opts":["CSLB","DLSE (Labor Commissioner)","EPA","Solo DIR Apprenticeship"],"re":"La DLSE / Labor Commissioner hace cumplir la ley de salarios y horas."},
  {"id":45,"q":"El seguro de responsabilidad general (general liability) para un contratista cubre principalmente:","opts":["Lesiones de empleados","Daños o lesiones que el contratista causa a otros/propiedad","Las propias herramientas del contratista","Penalizaciones fiscales"],"re":"El GL cubre lesiones corporales a terceros y daños a la propiedad causados por el trabajo del contratista."},
  {"id":46,"q":"El seguro de compensación de trabajadores cubre:","opts":["Daños a la casa de un cliente","Lesiones en el trabajo de los empleados del contratista","Materiales defectuosos","Incumplimiento de contrato"],"re":"La compensación de trabajadores paga las lesiones y enfermedades laborales de los empleados."},
  {"id":47,"q":"Un preliminary 20-day notice (aviso preliminar de 20 días) generalmente debe entregarse dentro de 20 días de:","opts":["Firmar el contrato","Proveer mano de obra o materiales por primera vez","Finalización del proyecto","Registrar un gravamen"],"re":"El aviso preliminar se entrega dentro de 20 días de proveer mano de obra/materiales por primera vez para preservar los derechos de gravamen."},
  {"id":48,"q":"Un mechanics lien (gravamen del constructor) es un recurso que se adhiere a:","opts":["La licencia del contratista","La propiedad inmueble mejorada","La cuenta bancaria del propietario","El permiso de construcción"],"re":"Un mechanics lien se adhiere a la propiedad inmueble que fue mejorada."},
  {"id":49,"q":"Si no se registra un Notice of Completion, un contratista directo (principal) debe registrar un mechanics lien dentro de:","opts":["30 días de la finalización","60 días de la finalización","90 días de la finalización","1 año de la finalización"],"re":"Sin un NOC, el contratista directo tiene 90 días después de la finalización para registrar un gravamen."},
  {"id":50,"q":"Después de registrar un mechanics lien, la demanda para ejecutarlo debe presentarse dentro de:","opts":["30 días","60 días","90 días","6 meses"],"re":"Una acción de ejecución del gravamen debe presentarse dentro de 90 días del registro, o el gravamen expira."},
  {"id":51,"q":"¿El propietario registra un Notice of Completion dentro de cuántos días de la finalización?","opts":["5 días","10 días","15 días","30 días"],"re":"El propietario registra el NOC dentro de 15 días de la finalización para acortar los plazos de presentación de gravámenes."},
  {"id":52,"q":"Una fianza que protege al propietario si el contratista no completa el trabajo es una:","opts":["Bid bond (fianza de oferta)","Performance bond (fianza de cumplimiento)","Payment bond (fianza de pago)","License bond (fianza de licencia)"],"re":"Una performance bond garantiza la finalización del contrato."},
  {"id":53,"q":"Una payment bond (fianza de pago) garantiza que:","opts":["El propietario recibe un reembolso","Los subcontratistas y proveedores reciban su pago","El contratista termine a tiempo","Se respete la oferta"],"re":"Una payment bond (fianza de mano de obra y materiales) asegura que los subcontratistas y proveedores reciban su pago."},
  {"id":54,"q":"Un documento mediante el cual un reclamante renuncia a los derechos de gravamen después del pago es un(a):","opts":["Stop notice","Liberación / renuncia de gravamen","Aviso preliminar","Aviso de cesación"],"re":"Una renuncia/liberación de gravamen cede los derechos de gravamen, normalmente a cambio del pago."},
  {"id":55,"q":"Para remover un gravamen registrado del título, un propietario puede registrar una fianza de garantía (release bond) por:","opts":["50% del gravamen","100% del gravamen","125% del gravamen","200% del gravamen"],"re":"Una fianza de liberación de gravamen es del 125% del monto del gravamen."},
  {"id":56,"q":"En obras privadas, el equivalente moderno del antiguo 'stop notice' es el:","opts":["Stop payment notice","Cese y desista (cease-and-desist)","Notice of nonresponsibility","Mechanics lien"],"re":"El 'stop payment notice' permite a un reclamante acceder a los fondos de construcción no desembolsados."},
  {"id":57,"q":"Para que un contrato sea válido, se requieren todos los siguientes EXCEPTO:","opts":["Consentimiento mutuo (oferta y aceptación)","Contraprestación (consideration)","Objeto lícito","El sello de un notario"],"re":"La mayoría de los contratos necesitan consentimiento, contraprestación, capacidad y un objeto lícito, no un notario."},
  {"id":58,"q":"Un contrato de mejoras al hogar (home improvement) en California debe ser por escrito cuando excede de:","opts":["$200","$500","$1,000","$5,000"],"re":"Los contratos de mejoras al hogar de más de $500 deben ser por escrito y firmados antes de comenzar el trabajo."},
  {"id":59,"q":"El pago inicial (down payment) máximo en un contrato de mejoras al hogar es el menor entre $1,000 o:","opts":["5% del contrato","10% del contrato","20% del contrato","25% del contrato"],"re":"El pago inicial está limitado al menor entre $1,000 o el 10% del precio del contrato."},
  {"id":60,"q":"El derecho de tres días del comprador a cancelar normalmente aplica a:","opts":["Todos los contratos","Contratos de venta a domicilio (puerta a puerta)","Solo obras públicas","Contratos verbales"],"re":"Las ventas a domicilio conllevan un derecho de rescisión de 3 días."},
  {"id":61,"q":"Una orden de cambio (change order) se describe mejor como:","opts":["Una nueva licencia","Una modificación por escrito al contrato original","Un tipo de fianza","Una liberación de gravamen"],"re":"Una orden de cambio documenta cambios acordados en el alcance, precio o tiempo, preferiblemente por escrito."},
  {"id":62,"q":"Un contrato que no puede ser legalmente ejecutado por ninguna de las partes es:","opts":["Anulable (voidable)","Nulo (void)","Expreso","Implícito"],"re":"Un contrato nulo (por ejemplo, con un propósito ilegal) no tiene efecto legal desde el inicio."},
  {"id":63,"q":"Un contrato anulable (voidable) es uno que:","opts":["Es ilegal","Una parte puede elegir afirmar o cancelar","No necesita contraprestación","Siempre es por escrito"],"re":"Un contrato anulable es válido hasta que la parte con el derecho elige rescindirlo (por ejemplo, el contrato de un menor)."},
  {"id":64,"q":"Una cláusula de daños liquidados (liquidated damages) especifica:","opts":["El monto de la fianza","Daños preacordados por incumplimiento (a menudo por día de retraso)","El pago inicial","El período de garantía"],"re":"Los daños liquidados establecen un monto razonable y acordado de daños por retraso o incumplimiento."},
  {"id":65,"q":"Una garantía expresa (express warranty) es una que:","opts":["Está implícita por ley","El contratista declara específicamente","La proporciona únicamente el fabricante","Nunca es ejecutable"],"re":"Una garantía expresa es una promesa específica hecha por escrito o de palabra."},
  {"id":66,"q":"El plazo de prescripción (statute of limitations) por incumplimiento de un contrato escrito en California es generalmente de:","opts":["1 año","2 años","4 años","10 años"],"re":"Las reclamaciones por contrato escrito generalmente deben presentarse dentro de 4 años."},
  {"id":67,"q":"Un contrato de mejoras al hogar debe incluir un aviso sobre:","opts":["El ID fiscal del contratista","El derecho del comprador a cancelar y la CSLB","El gravamen del banco","El sello del arquitecto"],"re":"El HIC debe contener los avisos requeridos al consumidor, incluyendo los derechos de cancelación y la información de la CSLB."},
  {"id":68,"q":"El 'cumplimiento sustancial' (substantial performance) generalmente significa que el contratista:","opts":["No hizo nada","Completó el propósito esencial con solo desviaciones menores","Incumplió el contrato","No tenía licencia"],"re":"El cumplimiento sustancial satisface el propósito esencial del contrato con solo defectos triviales y corregibles."},
  {"id":69,"q":"En proyectos de obras públicas, a los trabajadores generalmente se les debe pagar:","opts":["El salario mínimo","El prevailing wage (salario prevaleciente)","Lo que indique el contrato","Tarifa por pieza"],"re":"Las obras públicas requieren el pago del prevailing wage aplicable."},
  {"id":70,"q":"Para ofertar o trabajar en la mayoría de las obras públicas, un contratista debe estar registrado con el(la):","opts":["IRS","DIR (Department of Industrial Relations)","EPA","Solo la CSLB"],"re":"Los contratistas deben registrarse con el DIR para ofertar o realizar obras públicas."},
  {"id":71,"q":"Los registros de nómina certificada (certified payroll) en obras públicas se presentan para verificar:","opts":["Los costos de materiales","Que se pagaron los prevailing wages","Los montos de las fianzas","Las cuotas de permisos"],"re":"La nómina certificada documenta que los trabajadores recibieron los prevailing wages requeridos."},
  {"id":72,"q":"Una bid bond (fianza de oferta) en un proyecto de obras públicas garantiza que el:","opts":["Los subcontratistas reciban su pago","Postor ganador celebrará el contrato","Trabajo esté libre de defectos","Salario sea el prevaleciente"],"re":"Una bid bond le asegura a la agencia que el postor de menor oferta firmará el contrato y presentará las fianzas requeridas."},
  {"id":73,"q":"Las tarifas de prevailing wage son determinadas por el(la):","opts":["Contratista","Director of Industrial Relations","Solo el sindicato local","CSLB"],"re":"El Director del DIR establece las determinaciones de prevailing wage por oficio y localidad."},
  {"id":74,"q":"Todo empleador de California debe tener un(a) ___ por escrito:","opts":["Plan de marketing","Injury and Illness Prevention Program (IIPP)","Programa de ofertas","Registro de gravámenes"],"re":"Cal/OSHA requiere que todo empleador mantenga un IIPP por escrito."},
  {"id":75,"q":"Una lesión grave, enfermedad o muerte en el trabajo debe reportarse a Cal/OSHA dentro de:","opts":["8 horas","24 horas","48 horas","5 días"],"re":"Las lesiones graves/fatalidades deben reportarse a Cal/OSHA dentro de 8 horas."},
  {"id":76,"q":"Los procedimientos de 'lockout/tagout' se usan para:","opts":["Asegurar el sitio de trabajo de noche","Controlar la energía peligrosa durante el servicio/mantenimiento","Cerrar el remolque de herramientas","Etiquetar el trabajo terminado"],"re":"El LOTO aísla y desenergiza el equipo para que no pueda arrancar durante el servicio."},
  {"id":77,"q":"Una SDS (Safety Data Sheet) proporciona información sobre:","opts":["Tarifas salariales","Químicos peligrosos y su manejo seguro","Montos de fianzas","Códigos de construcción"],"re":"Las SDS describen los peligros de los químicos, su manejo y los primeros auxilios bajo el estándar de Hazard Communication."},
  {"id":78,"q":"La protección contra caídas generalmente se requiere en construcción a alturas de:","opts":["4 pies","6 pies","10 pies","20 pies"],"re":"En construcción, la protección contra caídas generalmente se requiere a 6 pies o más por encima de un nivel inferior."},
  {"id":79,"q":"Una 'competent person' (persona competente) bajo Cal/OSHA es alguien que puede:","opts":["Firmar contratos","Identificar peligros y tiene autoridad para corregirlos","Emitir licencias","Establecer el prevailing wage"],"re":"Una persona competente reconoce los peligros y está autorizada para tomar acciones correctivas inmediatas."},
  {"id":80,"q":"Antes de alterar más de 100 pies cuadrados de material que contiene asbesto, un contratista debe estar:","opts":["Afianzado por $50,000","Registrado con Cal/OSHA para trabajo con asbesto","Licenciado solo como C-22","Certificado EPA 608"],"re":"El trabajo con asbesto de más de 100 pies cuadrados requiere registro de asbesto con Cal/OSHA (y la certificación adecuada)."},
  {"id":81,"q":"El PPE (equipo de protección personal) generalmente es:","opts":["Comprado por el empleado","Proporcionado por el empleador cuando se requiere","Siempre opcional","Solo para obras públicas"],"re":"Los empleadores deben proporcionar el PPE requerido sin costo para los empleados."},
  {"id":82,"q":"Un espacio confinado que requiere permiso es peligroso principalmente debido a:","opts":["Solo el ruido","Peligros atmosféricos o de sepultamiento y salida limitada","El costo","Las temperaturas frías"],"re":"Los espacios confinados presentan peligros atmosféricos, de sepultamiento y de atrapamiento con salida restringida."},
  {"id":83,"q":"Un contratista que desea hacer plomería, electricidad y HVAC como una sola firma normalmente tendría:","opts":["Una sola C-20","Una B general building más las especialidades necesarias, o cada clasificación C","Un permiso de owner-builder","Ninguna licencia"],"re":"Múltiples oficios requieren las clasificaciones apropiadas (por ejemplo, licencias C separadas) o una general (B) calificadora donde se permita."},
  {"id":84,"q":"El propósito principal de la CSLB es:","opts":["Recaudar impuestos","Proteger al público regulando la industria de la construcción","Vender seguros","Establecer salarios sindicales"],"re":"La CSLB licencia y regula a los contratistas para proteger a los consumidores."},
  {"id":85,"q":"La publicidad debe incluir el(la) ___ del contratista:","opts":["Domicilio particular","Número de licencia","Compañía de fianzas","Declaración de impuestos"],"re":"Los contratistas licenciados deben mostrar su número de licencia en la publicidad."},
  {"id":86,"q":"La utilidad neta es:","opts":["Los ingresos antes de gastos","Los ingresos menos todos los gastos e impuestos","Los activos totales","Las aportaciones del propietario"],"re":"La utilidad neta es lo que queda después de todos los gastos e impuestos: el 'resultado final'."},
  {"id":87,"q":"Un balance general muestra la posición financiera de una empresa:","opts":["A lo largo de un año","En un solo punto en el tiempo","Solo en época de impuestos","Para un trabajo"],"re":"Un balance general es una instantánea de los activos, pasivos y capital en un momento dado."},
  {"id":88,"q":"Un aprendiz en un trabajo de obras públicas debe estar:","opts":["Sin pago","Registrado en un programa de aprendizaje aprobado","Mayor de 25 años","Ser dirigente sindical"],"re":"Los aprendices deben estar inscritos en un programa de aprendizaje aprobado por el estado para recibir tarifas de aprendiz."},
  {"id":89,"q":"No tener la compensación de trabajadores requerida puede resultar en:","opts":["Solo una advertencia","Una orden de cese (stop order) y suspensión de la licencia","Un crédito fiscal","Nada"],"re":"Operar sin la compensación de trabajadores requerida puede provocar una orden de cese, penalizaciones y suspensión de la licencia."},
  {"id":90,"q":"Un subcontratista que NO tuvo un contrato directo con el propietario normalmente debe entregar un aviso preliminar para preservar:","opts":["Derechos de afianzamiento","Derechos de gravamen y de stop-payment-notice","Derechos fiscales","Derechos de licencia"],"re":"Sin un contrato directo con el propietario, el aviso preliminar preserva los derechos de gravamen y de stop-payment del reclamante."},
  {"id":91,"q":"El seguro 'course of construction' (builder's risk) cubre:","opts":["Lesiones de empleados","El proyecto en sí durante la construcción","Accidentes automovilísticos","Disputas contractuales"],"re":"El builder's risk asegura la obra/materiales contra pérdidas durante la construcción."},
  {"id":92,"q":"Si un término del contrato es ambiguo, los tribunales a menudo lo interpretan:","opts":["A favor del contratista","En contra de la parte que lo redactó","Como nulo","A favor de la fianza"],"re":"Las ambigüedades generalmente se interpretan en contra del redactor."},
  {"id":93,"q":"Un error unilateral en una oferta (por ejemplo, un error de cálculo) puede permitir al postor:","opts":["Nunca retirarse","Buscar retirarse/rescindir si se cumplen las condiciones","Duplicar el precio libremente","Ignorar la oferta"],"re":"Un error unilateral genuino y material planteado oportunamente puede permitir la rescisión de la oferta."},
  {"id":94,"q":"En obras públicas, la agencia normalmente adjudica al:","opts":["Postor responsable y conforme de menor oferta","Postor de mayor oferta","Primer postor","Solo postor local"],"re":"Los contratos públicos generalmente se otorgan al postor responsable y conforme de menor oferta."},
  {"id":95,"q":"El prevailing wage generalmente NO aplica a:","opts":["La mayoría de las obras públicas por encima del umbral","Remodelaciones residenciales puramente privadas","Proyectos de edificios estatales","Trabajo de distritos escolares"],"re":"Los proyectos privados no son obras públicas, por lo que el prevailing wage generalmente no aplica."},
  {"id":96,"q":"Las reglas de prevención de enfermedades por calor en California requieren que los empleadores proporcionen:","opts":["Solo agua","Agua, sombra, descanso y capacitación","Aire acondicionado en el sitio","Bonos"],"re":"Los estándares de calor de Cal/OSHA requieren acceso a agua, sombra, descansos y capacitación."},
  {"id":97,"q":"Los andamios (scaffolding) que superan cierta altura deben ser:","opts":["Construidos por cualquiera","Diseñados/inspeccionados según Cal/OSHA y tener barandillas","Retirados a diario","Afianzados"],"re":"Los andamios deben cumplir con los requisitos de diseño, barandillas e inspección de Cal/OSHA."},
  {"id":98,"q":"Una licencia 'inactiva' significa que el contratista:","opts":["Aún puede ofertar","No puede contratar hasta reactivarla, pero conserva el número","Perdió la licencia","Debe impuestos atrasados"],"re":"Una licencia inactiva conserva el número pero no autoriza a contratar hasta que se reactive."},
  {"id":99,"q":"Se alcanza el punto de equilibrio (break-even) cuando:","opts":["Los ingresos superan a los activos","Los ingresos totales igualan a los costos totales","Los gastos generales son cero","La utilidad se maximiza"],"re":"El punto de equilibrio es donde los ingresos cubren exactamente los costos fijos más los variables: sin ganancia, sin pérdida."},
  {"id":100,"q":"Un contratista que abandona un trabajo sin excusa legal probablemente ha cometido:","opts":["Cumplimiento sustancial","Un incumplimiento material del contrato","Una orden de cambio","Una renuncia de gravamen"],"re":"El abandono injustificado es un incumplimiento material que expone al contratista a daños y perjuicios."},
  {"id":101,"q":"Si el PROPIETARIO registra un Aviso de Terminación (Notice of Completion), un SUBCONTRATISTA (no el contratista directo) debe registrar un gravamen del constructor (mechanics lien) dentro de:","opts":["10 días","30 días","60 días","90 días"],"re":"Con un NOC registrado, los subcontratistas/proveedores tienen 30 días; el contratista directo tiene 60 días."},
  {"id":102,"q":"Con un Aviso de Terminación (Notice of Completion) registrado, el contratista DIRECTO (principal) debe registrar un gravamen del constructor (mechanics lien) dentro de:","opts":["30 días","60 días","90 días","120 días"],"re":"El NOC acorta el plazo del contratista principal a 60 días (frente a 90 sin NOC)."},
  {"id":103,"q":"El propietario puede registrar un Aviso de Cese (Notice of Cessation) después de que el trabajo se haya detenido de forma continua durante al menos:","opts":["7 días","15 días","30 días","60 días"],"re":"Después de 30 días de cese continuo, el propietario puede registrar un Aviso de Cese, que (al igual que un NOC) acorta los plazos del gravamen."},
  {"id":104,"q":"El aviso preliminar de 20 días (preliminary 20-day notice) debe entregarse a todos los siguientes EXCEPTO:","opts":["El propietario","El contratista directo","El prestamista de construcción (si lo hay)","El recaudador de impuestos del condado"],"re":"El aviso preliminar se entrega al propietario, al contratista directo y al prestamista de construcción, no al recaudador de impuestos."},
  {"id":105,"q":"Por lo general, un contratista directo que SÍ contrató con el propietario:","opts":["Aún debe entregar un aviso preliminar al propietario","No necesita entregar un aviso preliminar al propietario (pero debe notificar a cualquier prestamista de construcción)","Pierde por completo los derechos de gravamen","No puede registrar un gravamen"],"re":"Un contratista directo no necesita entregar el aviso preliminar al propietario con quien contrató, pero debe notificar a cualquier prestamista de construcción."},
  {"id":106,"q":"El monto de un gravamen del constructor (mechanics lien) se limita a:","opts":["Siempre el precio total del contrato","El valor razonable del trabajo/materiales suministrados o el precio del contrato, el que sea menor","El doble del saldo impago","Cualquier cantidad que elija el reclamante"],"re":"Un gravamen se limita al menor entre el valor razonable suministrado o el precio del contrato, menos las cantidades pagadas."},
  {"id":107,"q":"Un \"Aviso de No Responsabilidad\" (Notice of Nonresponsibility) lo utiliza:","opts":["Un contratista que evita pagar salarios","Un propietario que no autorizó el trabajo de un inquilino, para proteger la propiedad de gravámenes","Un prestamista","Un subcontratista"],"re":"Un propietario registra un Aviso de No Responsabilidad para deslindar responsabilidad por mejoras que no autorizó (por ejemplo, trabajo de un inquilino)."},
  {"id":108,"q":"Una renuncia condicional de gravamen (conditional lien waiver) entra en vigor:","opts":["De inmediato al firmarla","Solo después de que el pago realmente se haya cobrado","Nunca","Después de 90 días"],"re":"Una renuncia condicional está supeditada a que el pago realmente se reciba/cobre."},
  {"id":109,"q":"Los formularios legales de renuncia de gravamen de California incluyen todos los siguientes EXCEPTO:","opts":["Renuncia condicional sobre pago parcial (progress payment)","Renuncia incondicional sobre pago parcial (progress payment)","Renuncia condicional sobre pago final","Gravamen permanente irrevocable"],"re":"Existen cuatro formularios legales (condicional/incondicional × parcial/final); el \"gravamen permanente irrevocable\" no es uno de ellos."},
  {"id":110,"q":"Si no se presenta una demanda de ejecución hipotecaria dentro de los 90 días posteriores al registro del gravamen, el gravamen:","opts":["Se duplica","Queda inejecutable/caduca","Se convierte en una fianza","Se transfiere al prestamista"],"re":"No demandar dentro de los 90 días deja el gravamen inejecutable y debe liberarse."},
  {"id":111,"q":"La Ley de Prácticas Justas de Subarrendamiento y Subcontratación (\"Listing Law\") exige que un postor principal en obras públicas:","opts":["Use solo subcontratistas sindicalizados","Liste a cada subcontratista que realice más del 0.5% de la oferta (o $10,000 en calles/carreteras)","Realice todo el trabajo por sí mismo","Pague a los subcontratistas por adelantado"],"re":"Los contratistas principales deben listar a los subcontratistas que realicen más de la mitad del 1% de la oferta total, para frenar el bid shopping."},
  {"id":112,"q":"El \"bid shopping\" se refiere a un contratista principal que, después de la adjudicación:","opts":["Compara cotizaciones de seguros","Presiona a los subcontratistas listados para que bajen los precios o los reemplaza indebidamente","Presenta un gravamen","Paga el salario prevaleciente (prevailing wage)"],"re":"El bid shopping consiste en usar una oferta baja para presionar o reemplazar subcontratistas después de adjudicado el contrato, restringido por la Listing Law."},
  {"id":113,"q":"Una vez que un subcontratista está listado, el contratista principal puede sustituirlo solo:","opts":["A su voluntad","Por una causa legal con el consentimiento de la autoridad adjudicadora","Si cambia el precio","Nunca"],"re":"La sustitución de un subcontratista listado requiere una razón legal reconocida y el consentimiento de la agencia pública."},
  {"id":114,"q":"La oferta de un subcontratista en la que el contratista principal confió razonablemente puede vincularlo bajo:","opts":["Quantum meruit","Promissory estoppel (impedimento promisorio)","Novación","Subrogación"],"re":"El promissory estoppel puede vincular a un subcontratista a una oferta en la que el contratista principal confió razonablemente en su propia oferta."},
  {"id":115,"q":"Una \"novación\" (novation) es:","opts":["Una orden de cambio menor","Sustituir un nuevo contrato/parte por uno antiguo, con el consentimiento de todas las partes","Una reclamación de fianza","Un gravamen"],"re":"La novación reemplaza un contrato o parte original por uno nuevo mediante acuerdo mutuo, extinguiendo la obligación anterior."},
  {"id":116,"q":"El \"quantum meruit\" permite recuperar:","opts":["Daños punitivos","El valor razonable de los servicios cuando no se fijó un precio exigible","Triples daños","Intereses del gravamen"],"re":"El quantum meruit otorga el valor razonable del trabajo realizado cuando no existe un precio contractual exigible."},
  {"id":117,"q":"Un contrato de mejoras al hogar (home improvement contract) debe contener un cronograma de pagos que esté:","opts":["100% por adelantado","Vinculado al valor del trabajo realizado y los materiales entregados","Pagado solo al final","Establecido por el prestamista"],"re":"Los pagos del HIC deben corresponder razonablemente al trabajo realizado y los materiales entregados, no concentrarse al inicio."},
  {"id":118,"q":"Para los contratos de servicio y reparación (exención específica), el límite del pago inicial en efectivo generalmente es:","opts":["Ningún límite especial más allá de la regla del HIC de $1,000/10%, a menos que se cumplan las condiciones de servicio y reparación","Siempre 50%","Siempre $5,000","Cero"],"re":"Se aplican los topes estándar de pago inicial del HIC, a menos que se cumplan las estrictas condiciones legales de \"servicio y reparación\"."},
  {"id":119,"q":"Un aviso de \"Advertencia de Gravamen del Constructor\" (Mechanics Lien Warning) debe entregarse al propietario:","opts":["Después de la terminación","Como parte de los documentos del contrato de mejoras al hogar","Solo en obras públicas","Nunca"],"re":"La documentación del HIC debe incluir el aviso requerido que informa a los propietarios sobre los derechos de gravamen del constructor de los subcontratistas/proveedores."},
  {"id":120,"q":"Bajo el Código B&P §7000 y siguientes, el registrador (registrar) puede emitir una citación que incluya:","opts":["Tiempo en la cárcel","Una orden de corrección y una sanción civil","Solo la revocación de la licencia","Solo multas penales"],"re":"Una citación de la CSLB puede ordenar corrección y imponer una sanción civil sin una audiencia disciplinaria completa."},
  {"id":121,"q":"El \"abandono\" (abandonment) de un proyecto de construcción sin justificación legal, según la ley de licencias, es:","opts":["Permitido si se paga","Causal de acción disciplinaria contra la licencia","Siempre un delito grave","Solo un asunto contractual"],"re":"El abandono intencional es una causal legal de disciplina por parte de la CSLB."},
  {"id":122,"q":"La desviación de los estándares aceptados del oficio (\"departure from plans/specs\") es sancionable cuando es:","opts":["Cualquier desviación","Intencional o fraudulenta y causa daño","Aprobada por el propietario","Un cambio cosmético menor"],"re":"La desviación intencional de los planos/especificaciones o de los estándares del oficio, que cause perjuicio, es causal de disciplina."},
  {"id":123,"q":"Ayudar a una persona sin licencia a evadir la ley de licencias es:","opts":["Permitido para amigos","Una infracción que puede conllevar disciplina","Permitido por debajo de $5,000","Alentado por la CSLB"],"re":"Ayudar a una persona sin licencia a contratar es en sí mismo una infracción de la ley de licencias."},
  {"id":124,"q":"La CSLB puede suspender una licencia automáticamente por un(a) impago de:","opts":["Una multa de estacionamiento","Una sentencia judicial relacionada con la construcción no pagada dentro de los 90 días","Una queja de marketing","Una declaración de impuestos tardía"],"re":"Una sentencia relacionada con la construcción no pagada puede provocar la suspensión automática si no se resuelve dentro de los 90 días."},
  {"id":125,"q":"El registrador (registrar) puede exigir una \"fianza disciplinaria\" (disciplinary bond) cuando un contratista:","opts":["Renueva a tiempo","Tiene un historial de infracciones/ha sido disciplinado","Solo está recién licenciado","Tiene seguro de responsabilidad civil general (GL)"],"re":"Se puede imponer una fianza disciplinaria a los licenciatarios con un historial de infracciones como condición para la licencia."},
  {"id":126,"q":"El plazo de prescripción para que la CSLB inicie la mayoría de las acciones disciplinarias generalmente es dentro de:","opts":["1 año del acto","4 años del acto (o 2 años para algunos), con reglas de descubrimiento","10 años","Sin límite alguno"],"re":"La disciplina de la CSLB generalmente debe iniciarse dentro de plazos establecidos (a menudo dentro de cuatro años del acto, sujeto a reglas de descubrimiento)."},
  {"id":127,"q":"Los gastos generales de un contratista son $90,000/año y la utilidad neta objetivo es $30,000. Para cubrir ambos sobre $600,000 de costos directos del trabajo, el margen de recargo (markup) necesario es de aproximadamente:","opts":["10%","20%","25%","33%"],"re":"($90k + $30k) ÷ $600k = 20% de recargo sobre los costos."},
  {"id":128,"q":"Si un trabajo se vende por $10,000 con un margen del 25% (sobre el precio), el costo fue:","opts":["$7,000","$7,500","$8,000","$8,500"],"re":"Margen sobre el precio: costo = $10,000 × (1 − 0.25) = $7,500."},
  {"id":129,"q":"El recargo (markup) y el margen difieren porque el recargo se calcula sobre el ____ y el margen sobre el ____:","opts":["precio; costo","costo; precio de venta","utilidad; ingresos","impuesto; ingreso"],"re":"El recargo es un porcentaje del costo; el margen es un porcentaje del precio de venta."},
  {"id":130,"q":"La \"retención\" (retention/retainage) en un contrato es:","opts":["Impuesto retenido","Un porcentaje de los pagos parciales que se retiene hasta la terminación","Una fianza","Horas extra"],"re":"La retención es una porción de cada pago que se retiene para asegurar la terminación, liberada al final."},
  {"id":131,"q":"Un contratista que utiliza el método de \"contrato terminado\" (completed-contract) reconoce la utilidad:","opts":["A medida que llega el efectivo","Cuando el contrato está sustancialmente terminado","Mensualmente","Al firmar"],"re":"El método de contrato terminado difiere el reconocimiento de la utilidad hasta que el trabajo está esencialmente terminado."},
  {"id":132,"q":"El método de \"porcentaje de terminación\" (percentage-of-completion) reconoce los ingresos:","opts":["Solo al final","En proporción al trabajo realizado durante el contrato","Nunca","Al momento de la oferta"],"re":"El método de porcentaje de terminación registra los ingresos a medida que avanza el proyecto."},
  {"id":133,"q":"Los pagos trimestrales de impuestos estimados al IRS generalmente se requieren para:","opts":["Empleados con W-2","Trabajadores autónomos/propietarios que esperan adeudar $1,000 o más en impuestos","Aprendices","Tenedores de fianzas"],"re":"Los trabajadores autónomos generalmente pagan impuestos estimados trimestralmente cuando esperan adeudar $1,000 o más."},
  {"id":134,"q":"En el 7.º día consecutivo de trabajo en una semana laboral, las primeras 8 horas se pagan a:","opts":["Tiempo normal","1.5×","2×","Sin pago"],"re":"Las primeras 8 horas en el 7.º día consecutivo se pagan a 1.5×; lo que exceda de 8 ese día se paga a 2×."},
  {"id":135,"q":"Un empleador debe registrarse en el EDD después de pagar salarios superiores a ____ en un trimestre calendario:","opts":["$100","$500","$1,000","$5,000"],"re":"Una vez que un empleador paga más de $100 en salarios en un trimestre, debe registrarse en el EDD."},
  {"id":136,"q":"El Formulario DE 9 / DE 9C presentado ante el EDD reporta:","opts":["Solo el impuesto federal sobre la renta","Salarios trimestrales e impuestos estatales sobre la nómina","Impuesto sobre las ventas","Gravámenes del constructor"],"re":"El DE 9 y el DE 9C reportan los salarios trimestrales y las contribuciones de impuestos sobre la nómina de California."},
  {"id":137,"q":"Una \"sanción por tiempo de espera\" (waiting time penalty) por salarios finales tardíos puede ser de hasta:","opts":["El pago de 1 día","El pago de 8 horas","30 días de salario","El salario de un año"],"re":"Los salarios finales pagados tardíamente de manera intencional pueden costar hasta 30 días del salario diario del empleado."},
  {"id":138,"q":"Bajo la prueba ABC, el criterio \"B\" exige que el trabajador realice un trabajo que sea:","opts":["Dentro del negocio habitual del contratante","Fuera del curso habitual del negocio de la entidad contratante","En obras públicas","Para miembros del sindicato"],"re":"El criterio B exige que el trabajo esté fuera del negocio habitual del contratante para ser contratista independiente."},
  {"id":139,"q":"Las exenciones de horas extra (por ejemplo, \"ejecutivo\") generalmente exigen que el empleado:","opts":["Solo tenga un título","Cumpla las pruebas de salario Y de funciones","Trabaje medio tiempo","Esté en obras públicas"],"re":"El estatus de exento exige cumplir tanto un umbral salarial mínimo como pruebas específicas de funciones."},
  {"id":140,"q":"Un empleador que paga en efectivo \"por debajo de la mesa\" para evadir los impuestos sobre la nómina arriesga:","opts":["Nada","Cargos por fraude fiscal, sanciones y disciplina de la licencia","Un reembolso","Un bono"],"re":"La nómina en efectivo no declarada expone al empleador a fraude fiscal, sanciones y disciplina de la CSLB."},
  {"id":141,"q":"Las licencias por enfermedad pagadas en California generalmente se acumulan a un mínimo de:","opts":["1 hora por cada 10 horas trabajadas","1 hora por cada 30 horas trabajadas","1 día por mes","Solo para empleados de tiempo completo"],"re":"La licencia por enfermedad pagada a nivel estatal se acumula al menos 1 hora por cada 30 horas trabajadas (verifique los mínimos locales actuales)."},
  {"id":142,"q":"El Formulario W-2 debe entregarse a los empleados a más tardar el:","opts":["15 de abril","31 de enero","30 de junio","31 de diciembre"],"re":"Los empleadores deben entregar los W-2 a los empleados a más tardar el 31 de enero."},
  {"id":143,"q":"En obras públicas, el umbral por encima del cual generalmente se requiere el registro DIR del contratista para nuevos proyectos es de aproximadamente:","opts":["$0","$15,000 (y $25,000 para adjudicaciones), sujeto a la ley vigente","$100,000","$1 millón"],"re":"Existen exenciones para proyectos pequeños (umbrales de aproximadamente $15,000 de trabajo / $25,000 de adjudicación); verifique las cifras actuales."},
  {"id":144,"q":"La nómina certificada (certified payroll) en obras públicas generalmente debe presentarse:","opts":["Una vez al final","Semanalmente (o según el cronograma de la agencia) a través del sistema eCPR del DIR","Anualmente","Nunca"],"re":"Los contratistas presentan los registros de nómina certificada (a menudo semanalmente) electrónicamente a través del DIR."},
  {"id":145,"q":"El salario prevaleciente (prevailing wage) incluye la tarifa básica por hora MÁS:","opts":["Solo las horas extra","Prestaciones complementarias (salud, pensión, capacitación)","Impuesto sobre las ventas","Primas de fianzas"],"re":"El salario prevaleciente es la tarifa básica más las contribuciones requeridas de prestaciones complementarias."},
  {"id":146,"q":"No pagar los salarios prevalecientes (prevailing wages) puede resultar en:","opts":["Una carta de agradecimiento","Sanciones, salarios atrasados e inhabilitación (debarment) de las obras públicas","Un crédito fiscal","Una mayor devolución de la fianza"],"re":"Pagar de menos los salarios prevalecientes puede acarrear sanciones, restitución e inhabilitación para licitar obras públicas."},
  {"id":147,"q":"Un Aviso de Suspensión de Pago (Stop Payment Notice) en un proyecto de obras PÚBLICAS se entrega a:","opts":["El registrador del condado","La entidad pública que retiene los fondos","La compañía afianzadora","El subcontratista"],"re":"En obras públicas no hay gravámenes contra la propiedad; un aviso de suspensión de pago alcanza los fondos retenidos por la entidad pública."},
  {"id":148,"q":"En obras públicas, en lugar de un gravamen del constructor, un subcontratista impago normalmente recurre a:","opts":["El título de la propiedad","La fianza de pago (payment bond) y/o el aviso de suspensión de pago","La vivienda del propietario","Solo la fianza de la CSLB"],"re":"La propiedad pública no puede gravarse; los recursos son la fianza de pago legal y el aviso de suspensión de pago."},
  {"id":149,"q":"Una fianza de pago de la \"Little Miller Act\" en obras públicas de California protege a:","opts":["Solo la agencia","Los subcontratistas y proveedores que quedan sin pago","La compañía afianzadora","Los contribuyentes frente a sobrecostos"],"re":"La fianza de pago requerida en obras públicas garantiza el pago a los subcontratistas y proveedores."},
  {"id":150,"q":"Una reclamación contra la fianza de la CSLB de un contratista generalmente se limita al daño causado por:","opts":["Cualquier disputa contractual","Infracciones específicas de la ley de licencias (por ejemplo, a consumidores/empleados)","Marketing","Asuntos fiscales"],"re":"La fianza del contratista cubre infracciones legales específicas que perjudican a propietarios de viviendas, empleados y ciertas otras personas."},
  {"id":151,"q":"Una cláusula de \"el tiempo es esencial\" (time is of the essence) significa que:","opts":["Los plazos son flexibles","El cumplimiento oportuno es un término material; el retraso es un incumplimiento","Solo importa el precio","La fianza controla los plazos"],"re":"Esta cláusula hace que las fechas de terminación sean materiales, por lo que el retraso constituye un incumplimiento."},
  {"id":152,"q":"Una disposición contractual que exige que las disputas se sometan a la decisión vinculante de un tercero neutral es:","opts":["Mediación","Arbitraje","Litigio","Estoppel (impedimento)"],"re":"El arbitraje somete la disputa a un neutral cuya decisión generalmente es vinculante."},
  {"id":153,"q":"La mediación difiere del arbitraje porque la mediación es:","opts":["Vinculante","No vinculante; el mediador ayuda a las partes a llegar a su propio acuerdo","Decidida por un juez","Solo para obras públicas"],"re":"Un mediador facilita un acuerdo voluntario y no impone una decisión."},
  {"id":154,"q":"La \"regla de la prueba extrínseca\" (parol evidence rule) limita el uso de:","opts":["Reclamaciones de fianza","Declaraciones orales previas para contradecir un contrato escrito completo","Avisos de gravamen","Órdenes de cambio"],"re":"La prueba extrínseca generalmente impide los términos orales previos/contemporáneos que contradigan un contrato escrito totalmente integrado."},
  {"id":155,"q":"Una \"garantía implícita de comerciabilidad\" (implied warranty of merchantability) significa que los bienes/materiales son:","opts":["Gratuitos","Aptos para su propósito ordinario","Siempre personalizados","Exentos de impuestos"],"re":"Los bienes comerciables son razonablemente aptos para los propósitos ordinarios para los que se utilizan."},
  {"id":156,"q":"La garantía estándar de mano de obra de un contratista en California a menudo se expresa como:","opts":["Sin garantía","Un año, independiente de los plazos legales de prescripción de defectos","Siempre de por vida","Solo lo que cubre la fianza"],"re":"Los contratistas comúnmente garantizan la mano de obra (por ejemplo, 1 año), además de los plazos legales de prescripción para defectos."},
  {"id":157,"q":"Para defectos de construcción latentes (ocultos), el plazo de prescripción (statute of repose) de California generalmente es de:","opts":["1 año","4 años","10 años","Sin límite"],"re":"Las reclamaciones por defectos latentes generalmente deben presentarse dentro de los 10 años posteriores a la terminación sustancial."},
  {"id":158,"q":"Para defectos de construcción patentes (evidentes), el plazo de prescripción generalmente es de:","opts":["1 año","4 años","10 años","20 años"],"re":"Los defectos patentes generalmente tienen un plazo de prescripción de 4 años."},
  {"id":159,"q":"La \"Right to Repair Act\" (SB 800) rige principalmente:","opts":["Los salarios de obras públicas","Las reclamaciones por defectos en construcciones residenciales nuevas y un proceso prejudicial","Los arrendamientos comerciales","La reparación de automóviles"],"re":"La SB 800 establece estándares y un proceso de aviso y reparación para defectos en construcciones residenciales nuevas."},
  {"id":160,"q":"Una cláusula de daños liquidados (liquidated damages) es inexigible si el monto establecido es:","opts":["Una estimación razonable","Una sanción irrazonable que excede ampliamente el daño probable","Por día","Acordado por escrito"],"re":"Los daños liquidados deben ser una previsión razonable del daño; un monto punitivo es inexigible."},
  {"id":161,"q":"Un contratista que permite que otra persona use su número de licencia para obtener permisos incurre en:","opts":["Un arreglo legal","\"Alquiler de licencia\" (license renting) ilegal, una infracción grave","Licenciamiento de empresa conjunta","Un arreglo de RME"],"re":"Prestar o \"alquilar\" un número de licencia es una infracción grave de la ley de licencias."},
  {"id":162,"q":"Para agregar una clasificación a una licencia existente, el calificador (qualifier) generalmente debe:","opts":["Pagar solo una tarifa","Aprobar el examen del oficio para esa clasificación (a menos que esté exento)","Esperar 5 años","Formar una nueva corporación"],"re":"Una nueva clasificación normalmente requiere aprobar el examen del oficio correspondiente (con exenciones limitadas)."},
  {"id":163,"q":"La exención de propietario-constructor (owner-builder) generalmente NO aplica cuando el propietario:","opts":["Construye para uso personal y no vende rápidamente","Construye con la intención de vender, excediendo los límites legales","Contrata subcontratistas con licencia","Vive en la vivienda"],"re":"La exención de propietario-constructor es limitada; construir estructuras para la venta más allá de los límites legales requiere una licencia."},
  {"id":164,"q":"Un contratista debe conservar los registros de nómina durante al menos (comúnmente):","opts":["30 días","6 meses","3 a 4 años (verifique según el tipo de registro)","Sin requisito"],"re":"Los registros de nómina e impuestos generalmente se conservan durante varios años (a menudo de 3 a 4); verifique según el tipo de registro y la agencia."},
  {"id":165,"q":"La responsabilidad de un empleador por los actos negligentes de un empleado dentro del ámbito de su empleo es:","opts":["Estoppel (impedimento)","Respondeat superior (responsabilidad indirecta)","Novación","Subrogación"],"re":"Bajo el respondeat superior, los empleadores son indirectamente responsables de la negligencia de los empleados en el trabajo."},
  {"id":166,"q":"La \"subrogación\" (subrogation) en seguros significa que la aseguradora:","opts":["Cancela la póliza","Asume los derechos del asegurado para recuperar de la parte culpable","Duplica la prima","Emite una fianza"],"re":"Después de pagar una reclamación, la aseguradora se subroga en los derechos de recuperación del asegurado contra la parte responsable."},
  {"id":167,"q":"Un endoso de \"asegurado adicional\" (additional insured) normalmente:","opts":["Asegura el camión del contratista","Extiende la cobertura de una póliza a otra parte (por ejemplo, el propietario/GC)","Reemplaza la indemnización laboral (workers' comp)","Paga gravámenes"],"re":"Extiende la protección de la póliza nombrada a otra parte, algo común en los requisitos de subcontratación."},
  {"id":168,"q":"Un \"certificado de seguro\" (certificate of insurance) es:","opts":["La póliza completa","Un resumen que comprueba la cobertura, no la póliza en sí","Una fianza","Una renuncia de gravamen"],"re":"Un COI resume la cobertura, pero por sí solo no confiere ni reemplaza los términos de la póliza."},
  {"id":169,"q":"Un recargo de \"utilidad y gastos generales\" (P&O / \"O&P\") en trabajos de restauración por seguro se cita comúnmente como:","opts":["5%","10% y 10% (≈20%)","50%","100%"],"re":"El O&P tradicional del contratista general en restauración a menudo se cita como 10% de gastos generales + 10% de utilidad."},
  {"id":170,"q":"El \"costo de los bienes vendidos\" (cost of goods sold) de un contratista en un trabajo incluiría:","opts":["Renta de oficina","Mano de obra directa, materiales y subcontratos de ese trabajo","El salario del propietario","Marketing"],"re":"El COGS captura los costos directos del trabajo: mano de obra, materiales, equipo y subcontratistas de ese proyecto."},
  {"id":171,"q":"Una cláusula de \"pago cuando se pague\" (pay-when-paid) generalmente se interpreta en California como:","opts":["Una condición que elimina el derecho del subcontratista al pago","Una disposición de plazo razonable; el subcontratista aún debe ser pagado eventualmente","Siempre nula","Idéntica al pay-if-paid y exigible"],"re":"California desaprueba las verdaderas condiciones de \"pay-if-paid\"; el \"pay-when-paid\" se interpreta como un plazo razonable para pagar."},
  {"id":172,"q":"Un contratista NO puede hacer cumplir una cláusula del contrato que exija que el comprador renuncie a:","opts":["El pago inicial","Protecciones legales al consumidor / derechos de gravamen por adelantado, donde esté prohibido","La fecha de terminación","La garantía"],"re":"Las renuncias anticipadas de ciertas protecciones legales (por ejemplo, derechos de gravamen) son inexigibles donde la ley lo prohíbe."},
  {"id":173,"q":"Un \"acuerdo laboral de proyecto\" (project labor agreement, PLA) en obras públicas es:","opts":["Una fianza","Un acuerdo de negociación colectiva previo a la contratación que establece términos para el proyecto","Un gravamen","Un permiso"],"re":"Un PLA es un acuerdo previo a la contratación que establece los términos laborales para un proyecto público específico."},
  {"id":174,"q":"Los requisitos de \"proporción\" (ratio) de aprendizaje en obras públicas significan que:","opts":["No se permiten aprendices","Debe cumplirse una proporción establecida de horas de aprendiz a oficial (journeyman)","Solo trabajan oficiales (journeymen)","Los aprendices no reciben pago"],"re":"Las obras públicas a menudo exigen emplear aprendices en una proporción definida respecto a las horas de oficial (journeyman)."},
  {"id":175,"q":"Una citación por \"infracción grave\" (serious violation) de Cal/OSHA significa:","opts":["Un error de papeleo","Una probabilidad sustancial de muerte o daño físico grave","Un problema menor de limpieza","Un error de publicidad"],"re":"Una infracción grave implica una probabilidad realista de muerte o daño físico grave."},
  {"id":176,"q":"Una infracción \"intencional\" (willful) de Cal/OSHA conlleva sanciones más altas porque el empleador:","opts":["Cometió un error honesto","Conocía el requisito y lo desatendió intencionalmente","Era una pequeña empresa","No tenía empleados"],"re":"Las infracciones intencionales implican un desprecio deliberado o una indiferencia evidente hacia un requisito conocido."},
  {"id":177,"q":"El Formulario 300 de Cal/OSHA se utiliza para:","opts":["Declarar impuestos","Registrar las lesiones y enfermedades laborales registrables","Solicitar una licencia","Registrar gravámenes"],"re":"El registro del Formulario 300 anota las lesiones y enfermedades relacionadas con el trabajo; el 300A es el resumen anual."},
  {"id":178,"q":"Las excavaciones de 5 pies o más de profundidad generalmente requieren:","opts":["Ninguna precaución","Un sistema de protección (talud, apuntalamiento o blindaje) a menos que sea roca estable","Una fianza","Solo un permiso"],"re":"Las zanjas/excavaciones de 5 pies o más necesitan protección contra derrumbes, a menos que se realicen completamente en roca estable."},
  {"id":179,"q":"Generalmente se requiere un permiso de excavación de Cal/OSHA para zanjas más profundas de:","opts":["3 pies","5 pies","10 pies (para el permiso; la protección aún se necesita a los 5 pies)","20 pies"],"re":"Generalmente se requiere un permiso de Cal/OSHA para zanjas/excavaciones de 5 pies de profundidad donde los trabajadores ingresan; un permiso anual cubre la mayoría; los permisos por proyecto aplican a trabajos más profundos (verifique la regla actual)."},
  {"id":180,"q":"Antes de excavar, un contratista debe comunicarse con el centro regional de notificación (llamar/hacer clic en 811) para:","opts":["Pedir materiales","Que se marquen las instalaciones subterráneas (DigAlert)","Obtener una licencia","Presentar un gravamen"],"re":"Llamar al 811/DigAlert antes de excavar permite localizar y marcar las instalaciones para evitar daños."},
  {"id":181,"q":"Si el único RMO calificador de una corporación se va, la licencia:","opts":["No se ve afectada","Queda sujeta a suspensión si no se reemplaza dentro del período permitido","Se revoca automáticamente el mismo día","Se convierte en una empresa unipersonal"],"re":"Perder al calificador puede llevar a la suspensión si no se reporta un reemplazo dentro del plazo legal (por ejemplo, 90 días)."},
  {"id":182,"q":"Un contratista debe reportar una condena o ciertas acciones adversas sobre su licencia a la CSLB porque:","opts":["Es opcional","No divulgarlo es en sí mismo una infracción","La CSLB nunca lo pregunta","Solo los delitos graves importan para la publicidad"],"re":"Los licenciatarios tienen el deber de reportar ciertas condenas/acciones; el ocultamiento es una infracción."},
  {"id":183,"q":"Un contrato de \"precio fijo\" (suma global) coloca el riesgo de sobrecostos principalmente en:","opts":["El propietario","El contratista","El prestamista","La compañía afianzadora"],"re":"En un contrato de suma global, el contratista asume el riesgo de sobrecostos para el alcance acordado."},
  {"id":184,"q":"Un contrato de \"costo más\" (cost-plus) reembolsa los costos más una tarifa, trasladando el riesgo de sobrecostos hacia:","opts":["El contratista","El propietario","El subcontratista","La aseguradora"],"re":"El cost-plus traslada más riesgo de sobrecostos al propietario, que paga los costos reales más la tarifa."},
  {"id":185,"q":"Un \"alcance del trabajo\" (scope of work) que es vago lo más frecuente es que conduzca a:","opts":["Un precio más bajo","Disputas y conflictos por órdenes de cambio","Una terminación más rápida","Reclamaciones de fianza por parte del propietario"],"re":"Un alcance vago genera desacuerdos sobre lo que está incluido, provocando disputas y órdenes de cambio."},
  {"id":186,"q":"En un contrato de mejoras al hogar, el precio total del contrato debe:","opts":["Solo estimarse","Indicarse como una cantidad específica en dólares (o un método claro para calcularlo)","Ocultarse hasta la terminación","Establecerse por el prestamista"],"re":"Los HIC deben indicar el precio total con claridad para que el consumidor conozca el costo completo."},
  {"id":187,"q":"El estatus de contratista independiente es MENOS respaldado cuando el trabajador:","opts":["Tiene su propia licencia y herramientas","Establece sus propios horarios","Trabaja solo para un contratante, realizando el trabajo central del contratante, bajo su dirección","Factura por proyectos"],"re":"Trabajar exclusivamente para un contratante, en su negocio central y bajo su control, apunta a un estatus de empleado."},
  {"id":188,"q":"Un contratista C-20 que contrata ayudantes y les paga por hora bajo su dirección ha creado:","opts":["Contratistas independientes","Una relación empleador-empleado que requiere cumplimiento de la nómina","Una sociedad","Una empresa conjunta"],"re":"Los ayudantes por hora bajo el control del contratista son empleados, lo que genera obligaciones de impuestos sobre la nómina e indemnización laboral."},
  {"id":189,"q":"El incumplimiento de un contratista en mantener la fianza requerida resulta en:","opts":["Solo una advertencia","Suspensión de la licencia hasta que se restablezca la fianza","Una sanción fiscal","Nada"],"re":"La licencia se suspende si caduca la fianza requerida, hasta que se restablezca la cobertura."},
  {"id":190,"q":"Una \"fianza de terminación\" (completion bond) difiere de una fianza de cumplimiento en que principalmente garantiza:","opts":["El pago a los subcontratistas","Al prestamista/propietario que el proyecto se terminará libre de gravámenes","El salario prevaleciente","El precio de la oferta"],"re":"Una fianza de terminación garantiza a las partes financieras que el proyecto se completará y quedará libre de gravámenes."},
  {"id":191,"q":"En obras públicas, falsificar la nómina certificada (certified payroll) es:","opts":["Un asunto administrativo","Una ofensa grave que puede conllevar sanciones, inhabilitación (debarment) y exposición penal","Alentado","Permitido por debajo de $25,000"],"re":"Falsificar la nómina certificada puede acarrear sanciones civiles, inhabilitación y responsabilidad penal."},
  {"id":192,"q":"Una agencia pública puede retener los pagos del contrato para hacer cumplir:","opts":["Reglas de marketing","El cumplimiento del salario prevaleciente y de las leyes laborales","Renovaciones de fianzas","Anuncios de licencia"],"re":"Las agencias pueden retener pagos para asegurar el cumplimiento del salario prevaleciente y de las leyes laborales."},
  {"id":193,"q":"El uso de respiradores en un trabajo con riesgos respiratorios requiere:","opts":["Cualquier mascarilla","Un programa escrito de protección respiratoria con pruebas de ajuste y evaluación médica","Nada para tareas cortas","Solo protección ocular"],"re":"El uso requerido de respiradores activa un programa escrito, autorización médica y pruebas de ajuste."},
  {"id":194,"q":"El \"derecho a saber\" (right to know) del estándar de Comunicación de Peligros cubre el acceso de los empleados a:","opts":["La nómina","Información sobre peligros químicos, etiquetas y SDS","Detalles de la fianza","Resultados de licitaciones"],"re":"La HazCom garantiza a los trabajadores información sobre los peligros químicos mediante etiquetas, SDS y capacitación."},
  {"id":195,"q":"La protección GFCI en sitios de construcción se requiere para prevenir:","opts":["Horas extra","Descargas eléctricas por fallas a tierra","Robos","Ruido"],"re":"Los interruptores de circuito por falla a tierra (GFCI) protegen a los trabajadores de descargas debidas a fallas a tierra."},
  {"id":196,"q":"La \"Ley de Licencias de Contratistas del Estado\" (Contractors State License Law) se encuentra principalmente en el Código de California de:","opts":["Código Penal","Código de Negocios y Profesiones (B&P §7000 y siguientes)","Código Vehicular","Código Tributario"],"re":"La ley de licencias está en el Código B&P a partir del §7000."},
  {"id":197,"q":"Un contratista que constantemente oferta por debajo del costo y se queda sin efectivo a mitad del proyecto lo más probable es que haya fallado en:","opts":["Marketing","La estimación y la planificación del flujo de efectivo","Seguridad","Presentación de gravámenes"],"re":"La oferta crónica por debajo del costo y la falta de efectivo apuntan a una estimación y gestión del flujo de efectivo deficientes."},
  {"id":198,"q":"Una \"cláusula de integración\" (integration clause) en un contrato establece que el documento escrito:","opts":["Puede modificarse oralmente en cualquier momento","Es el acuerdo completo y final de las partes","Es solo una estimación","No necesita firmas"],"re":"Una cláusula de integración (fusión) confirma que el escrito es el acuerdo completo y final de las partes."},
  {"id":199,"q":"Un contratista que obtiene un permiso pero deja que una persona sin licencia haga la contratación real puede enfrentar:","opts":["Ningún problema","Disciplina por ayudar a actividad sin licencia e infracciones de la ley de licencias","Un reembolso de impuestos","Solo un aumento de la fianza"],"re":"Servir de fachada con permisos para trabajo sin licencia infringe la ley de licencias y provoca disciplina."},
  {"id":200,"q":"La mejor protección individual contra disputas de pago en un trabajo de mejoras al hogar es:","opts":["Una promesa verbal","Un contrato escrito claro con alcance, precio y cronograma de pagos definidos","Un pago inicial más grande","Una fianza más grande"],"re":"Un contrato escrito claro y completo, alineado con el trabajo realizado, es la defensa más sólida contra disputas de pago."},
  {"id":201,"q":"Un empleado que renuncia CON al menos 72 horas de aviso debe recibir su pago final:","opts":["Dentro de las 72 horas siguientes","En el siguiente día de pago regular","En su último día de trabajo","Dentro de 30 días"],"re":"Con 72 horas o más de aviso, el pago final se debe entregar en el último día de trabajo del empleado."},
  {"id":202,"q":"Pago por presentarse a trabajar (reporting-time pay): a un empleado que se presenta según lo programado pero es enviado a casa temprano se le debe pagar por lo menos:","opts":["1 hora","La mitad del turno programado (mínimo 2, máximo 4 horas)","El turno completo","Nada"],"re":"El pago por presentarse a trabajar es la mitad del turno programado, con un mínimo de 2 y un máximo de 4 horas a la tarifa regular."},
  {"id":203,"q":"En California, la prima por 'turno dividido' (split shift) generalmente es:","opts":["Tiempo doble","Una hora adicional al salario mínimo","Sin prima","Tiempo y medio"],"re":"Cuando un horario se divide por tiempo no pagado que no es de comida, el empleador debe una hora adicional al salario mínimo (aplican reglas de compensación)."},
  {"id":204,"q":"Si un empleador no proporciona un período de comida o descanso requerido, la penalización es:","opts":["Una advertencia por escrito","Una hora adicional de pago a la tarifa regular","Despido","Nada"],"re":"Un período de comida o descanso omitido genera una hora de prima a la tarifa regular (una por categoría por día)."},
  {"id":205,"q":"El formulario de reporte de nuevas contrataciones de California que se presenta ante la EDD es el:","opts":["DE 9","DE 34","DE 542","W-2"],"re":"El formulario DE 34 reporta a los empleados recién contratados a la EDD dentro de 20 días."},
  {"id":206,"q":"Los contratistas independientes a quienes se les paga $600 o más se reportan a la EDD en el:","opts":["DE 34","DE 542","Formulario I-9","Formulario 940"],"re":"El formulario DE 542 reporta a la EDD los pagos por servicios de contratistas independientes de $600 o más."},
  {"id":207,"q":"El impuesto federal de desempleo (FUTA) se reporta anualmente en el formulario del IRS:","opts":["Formulario 941","Formulario 940","Formulario W-4","Formulario 1099"],"re":"El formulario 940 reporta el FUTA anual; el formulario 941 reporta la retención trimestral y el FICA."},
  {"id":208,"q":"La prima del seguro de compensación al trabajador (worker's compensation) se basa principalmente en:","opts":["El número de camiones","La nómina, los códigos de clasificación y el modificador de experiencia","Los pies cuadrados","El monto de la fianza"],"re":"Prima de WC = nómina × tarifa del código de clase × modificador de experiencia (X-Mod)."},
  {"id":209,"q":"Un 'modificador de experiencia' (X-Mod) por encima de 1.0 significa que el historial de reclamos del empleador es:","opts":["Mejor que el promedio (reduce la prima)","Peor que el promedio (aumenta la prima)","Irrelevante","Deducible de impuestos"],"re":"Un X-Mod por encima de 1.0 refleja pérdidas peores que el promedio y aumenta la prima de WC."},
  {"id":210,"q":"Un comprobante de pago detallado (talón de pago) bajo el Labor Code §226 debe incluir:","opts":["Solo el pago neto","Salario bruto, horas, tarifas, deducciones, fechas e información del empleador","Solo el nombre del empleado","El número de la fianza"],"re":"El §226 requiere nueve elementos específicos, incluidos el salario bruto/neto, las horas, las tarifas, las deducciones, el período de pago y la identidad del empleador."},
  {"id":211,"q":"Un subcontratista con licencia que realiza trabajo bajo su propia licencia generalmente es:","opts":["Su empleado","No es su empleado para fines de nómina/WC","Siempre un aprendiz","Exento del salario prevaleciente"],"re":"Un subcontratista con licencia genuino que opera su propio negocio no es empleado del contratista principal para fines de nómina y compensación al trabajador."},
  {"id":212,"q":"Para el tiempo extra, la 'tarifa regular de pago' de un empleado debe incluir:","opts":["Solo el salario base por hora","Bonos no discrecionales y ciertos incentivos","Solo las propinas","El reembolso de millaje"],"re":"La tarifa regular utilizada para el tiempo extra incluye los bonos no discrecionales y el pago de incentivos, no solo el salario base."},
  {"id":213,"q":"El salario mínimo estatal de California vigente a partir del 1 de enero de 2026 es:","opts":["$15.50/hr","$16.50/hr","$16.90/hr","$20.00/hr"],"re":"El salario mínimo estatal es de $16.90/hr en 2026 (las tarifas locales y por industria pueden ser más altas)."},
  {"id":214,"q":"El salario mínimo de 2026 para un empleado exento de tiempo completo en California es:","opts":["$54,080","$66,560","$70,304","$100,000"],"re":"Los empleados exentos deben ganar al menos 2× el salario mínimo a tiempo completo = $70,304/año en 2026."},
  {"id":215,"q":"Los formularios I-9 deben conservarse durante:","opts":["1 año desde la contratación","3 años desde la contratación o 1 año después de la terminación, lo que ocurra después","Para siempre","Hasta la próxima auditoría"],"re":"Conserve los I-9 durante 3 años después de la contratación o 1 año después de la terminación, lo que ocurra después."},
  {"id":216,"q":"Los beneficios del Permiso Familiar Pagado de California (PFL) se financian a través de:","opts":["El empleador directamente","Deducciones de SDI del salario del empleado","Subvenciones federales","La compensación al trabajador"],"re":"El PFL es parte del programa de SDI, financiado por deducciones del salario del empleado."},
  {"id":217,"q":"Los carteles obligatorios de las leyes laborales estatales y federales deben:","opts":["Enviarse por correo electrónico cada año","Exhibirse donde los empleados puedan verlos con facilidad","Presentarse ante la CSLB","Ser opcionales para empresas pequeñas"],"re":"Los empleadores deben colocar los avisos vigentes de las leyes laborales en un lugar visible del lugar de trabajo."},
  {"id":218,"q":"El permiso por enfermedad pagado obligatorio generalmente permite a los empleadores limitar el uso anual a:","opts":["8 horas","24 horas / 3 días (o 40/5 bajo reglas más nuevas — verificar)","Sin límite","80 horas"],"re":"Los empleadores pueden limitar el uso (históricamente 24 horas/3 días; una ley más nueva aumentó los mínimos — verificar el valor vigente)."},
  {"id":219,"q":"Contratar a un trabajador, controlar sus horas y proporcionarle herramientas con mayor probabilidad lo convierte en un(a):","opts":["Contratista independiente","Empleado","Proveedor","Socio"],"re":"El control sobre las horas, las herramientas y el método apunta a la condición de empleado bajo la prueba ABC."},
  {"id":220,"q":"El incumplimiento intencional de pagar todos los salarios adeudados al momento de la separación puede generar:","opts":["Un bono","Penalizaciones por tiempo de espera de hasta 30 días de salario","Un crédito fiscal","Nada"],"re":"Los salarios finales no pagados pueden costar hasta 30 días del pago diario del trabajador como penalización."},
  {"id":221,"q":"Un proyecto de obra pública debe registrarse ante el DIR usando el formulario:","opts":["DAS-140","PWC-100","DE 34","CF-1R"],"re":"La entidad adjudicadora registra el proyecto mediante el PWC-100 ante el DIR."},
  {"id":222,"q":"En obra pública, un contratista notifica a los comités de aprendizaje sobre la adjudicación de un contrato usando:","opts":["DAS-140","DAS-142","DE 542","CF-3R"],"re":"El formulario DAS-140 da aviso de la adjudicación del contrato a los comités de aprendizaje correspondientes."},
  {"id":223,"q":"Para solicitar el envío de aprendices en un trabajo de obra pública, un contratista presenta:","opts":["DAS-140","DAS-142","PWC-100","Formulario 940"],"re":"El formulario DAS-142 solicita el envío de aprendices del comité."},
  {"id":224,"q":"El salario prevaleciente generalmente se aplica a los contratos de obra pública superiores a:","opts":["$1,000","$15,000","$25,000","$100,000"],"re":"El salario prevaleciente se aplica a las obras públicas de más de $1,000 (con exenciones de registro limitadas para trabajos pequeños)."},
  {"id":225,"q":"La proporción de horas de trabajo de aprendiz a oficial (journeyman) en obra pública generalmente no es menor que:","opts":["1 hora de aprendiz por cada 5 horas de oficial","1 por cada 2","1 por cada 10","Sin proporción"],"re":"Las obras públicas generalmente requieren al menos 1 hora de trabajo de aprendiz por cada 5 horas de trabajo de oficial."},
  {"id":226,"q":"Las determinaciones de salario prevaleciente se basan en:","opts":["El salario mínimo federal","La tarifa básica por hora más los pagos de prestaciones del empleador por oficio y localidad","La elección del contratista","Las cuotas sindicales"],"re":"Las determinaciones establecen la tarifa básica más las contribuciones de prestaciones para cada oficio y área."},
  {"id":227,"q":"La violación intencional de la ley de salario prevaleciente puede resultar en la inhabilitación de obras públicas por:","opts":["30 días","1 a 3 años","10 años","Solo de forma permanente"],"re":"Las violaciones intencionales pueden conllevar una inhabilitación de 1 a 3 años (más prolongada en casos reincidentes/graves)."},
  {"id":228,"q":"La nómina certificada en obra pública se presenta electrónicamente a través de:","opts":["El portal del IRS","El sistema eCPR del DIR","La CSLB","El registrador del condado"],"re":"Los contratistas presentan los registros de nómina certificada a través del sistema electrónico eCPR del DIR."},
  {"id":229,"q":"En obra pública, el tiempo extra se debe según:","opts":["Solo después de 40 horas/semana","Las horas especificadas en la determinación de salario prevaleciente aplicable (a menudo después de 8/día)","Nunca","La política del contratista"],"re":"El tiempo extra en obra pública sigue la determinación — comúnmente después de 8 horas/día y en fines de semana/días festivos."},
  {"id":230,"q":"El pago de viáticos y subsistencia en obra pública es:","opts":["Nunca se debe","Se debe cuando se especifica en la determinación de salario prevaleciente","Siempre tiempo doble","Lo paga el trabajador"],"re":"Los viáticos/subsistencia se deben cuando la determinación aplicable lo requiere."},
  {"id":231,"q":"El Título 24 del Código de Regulaciones de California es el:","opts":["Código fiscal","Código de Normas de Construcción de California (incl. energía y mecánica)","Código laboral","Código de vehículos"],"re":"El Título 24 es el Código de Normas de Construcción, que cubre energía (Parte 6), mecánica (Parte 4), CALGreen (Parte 11) y más."},
  {"id":232,"q":"En California, un permiso de construcción para el reemplazo (changeout) de un sistema HVAC generalmente es:","opts":["No requerido","Requerido, y el contratista con licencia normalmente lo tramita","Tramitado solo por el propietario","Opcional"],"re":"La mayoría de los reemplazos de HVAC requieren un permiso; el contratista con licencia normalmente lo tramita para el trabajo que realiza."},
  {"id":233,"q":"Bajo el cumplimiento energético del Título 24, el certificado de cumplimiento de un proyecto es el:","opts":["CF-1R","CF-2R","CF-3R","DAS-140"],"re":"El CF-1R es el Certificado de Cumplimiento; el CF-2R es de instalación; el CF-3R es de verificación de campo HERS."},
  {"id":234,"q":"Un evaluador HERS en un trabajo de HVAC residencial normalmente verifica:","opts":["La fianza","Las fugas en los ductos y la carga de refrigerante / el flujo de aire","El precio del contrato","La nómina"],"re":"La verificación HERS confirma elementos como las fugas en los ductos y la carga de refrigerante/flujo de aire según el Título 24."},
  {"id":235,"q":"Realizar trabajo con permiso sin solicitar la inspección final requerida significa que el trabajo está:","opts":["Legalmente completo","No completado correctamente y puede violar el código","Exento del Título 24","Aprobado automáticamente"],"re":"Sin las inspecciones/aprobación final requeridas, el trabajo no está completado correctamente bajo el código."},
  {"id":236,"q":"Realizar trabajo que requiere un permiso sin obtenerlo puede resultar en:","opts":["Un descuento","Tarifas dobles de permiso y posibles medidas disciplinarias","Un crédito fiscal","Nada"],"re":"El trabajo que requiere permiso realizado sin uno a menudo incurre en tarifas de penalización (p. ej., dobles) y exposición ante la CSLB."},
  {"id":237,"q":"El Código Mecánico de California se encuentra en el Título 24, Parte:","opts":["Parte 2","Parte 4","Parte 6","Parte 11"],"re":"La Parte 4 es el Código Mecánico de California; la Parte 6 es Energía; la Parte 11 es CALGreen."},
  {"id":238,"q":"Un RMO/RME generalmente puede servir como calificador (qualifier) para:","opts":["Empresas ilimitadas","Solo una empresa a la vez (con excepciones limitadas basadas en la propiedad)","Exactamente tres empresas","Solo agencias públicas"],"re":"Un calificador generalmente está limitado a una sola licencia, con excepciones limitadas para empresas con propiedad en común."},
  {"id":239,"q":"Una licencia que no se renueva en su fecha de vencimiento puede renovarse de forma tardía, pero con un(a):","opts":["Sin penalización","Penalización por renovación morosa (p. ej., 50% de la tarifa)","Prohibición permanente","Nuevo examen"],"re":"La renovación tardía conlleva una penalización por morosidad (comúnmente la mitad de la tarifa de renovación) durante un período limitado."},
  {"id":240,"q":"Cambiar la entidad comercial (p. ej., de propietario único a corporación) generalmente requiere:","opts":["Ninguna acción","Una nueva licencia para la nueva entidad","Solo un formulario de cambio de nombre","Solo un aumento de la fianza"],"re":"Una entidad legal diferente necesita su propia licencia; no se puede transferir una licencia entre entidades."},
  {"id":241,"q":"Una persona que vende contratos de mejoras del hogar para un contratista en el campo debe registrarse como:","opts":["Notario","Vendedor de Mejoras del Hogar (HIS)","Agente de bienes raíces","Ajustador público"],"re":"Los Vendedores de Mejoras del Hogar deben estar registrados ante la CSLB."},
  {"id":242,"q":"Un contrato de mejoras del hogar debe incluir:","opts":["Solo un precio total","Las fechas aproximadas de inicio y finalización y un cronograma de pagos","El sello del arquitecto","El logotipo del prestamista"],"re":"Los contratos de mejoras del hogar (HIC) deben indicar las fechas aproximadas de inicio/finalización, el precio y un cronograma de pagos basado en el trabajo."},
  {"id":243,"q":"Una cláusula de arbitraje en un contrato de mejoras del hogar generalmente debe estar:","opts":["Oculta en letra pequeña","Claramente divulgada y aceptada/firmada con iniciales por separado","Solo de forma verbal","Omitida"],"re":"Las disposiciones de arbitraje obligatorio en los HIC para consumidores deben divulgarse y reconocerse de forma visible."},
  {"id":244,"q":"El aviso del derecho a cancelar dentro de los tres días debe estar:","opts":["Mencionado verbalmente","Adjunto al contrato con los formularios de cancelación","Presentado ante la CSLB","Publicado en línea"],"re":"El comprador debe recibir el aviso de cancelación y los formularios junto con el contrato."},
  {"id":245,"q":"Aceptar un pago inicial excesivo en un contrato de mejoras del hogar es:","opts":["Permitido si el cliente está de acuerdo","Una violación de la ley de licencias","Práctica estándar","Requerido por los prestamistas"],"re":"Exceder el límite del pago inicial es una violación, incluso con el consentimiento del cliente."},
  {"id":246,"q":"El 'inicio sustancial' del trabajo significa que el contratista debe:","opts":["Solo firmar el contrato","Hacer un comienzo genuino y proseguir el trabajo con diligencia","Esperar el pago completo","Solo pedir materiales"],"re":"Después de tomar un depósito, el contratista debe comenzar sustancialmente y proseguir el trabajo con diligencia."},
  {"id":247,"q":"Un servicio de 'control de fondos' (control conjunto) en un proyecto se usa para:","opts":["Fijar precios","Desembolsar los fondos de construcción a medida que avanza el trabajo para proteger contra el desvío","Tramitar permisos","Presentar gravámenes"],"re":"El control conjunto/de fondos libera los pagos según el avance, reduciendo el riesgo de uso indebido de los fondos."},
  {"id":248,"q":"Un contratista NO puede incluir en un contrato con el consumidor una cláusula que:","opts":["Indique el precio","Renuncie por adelantado a los derechos de cancelación legales del comprador","Enumere los materiales","Establezca un cronograma"],"re":"Las renuncias por adelantado a las protecciones obligatorias del consumidor (como los derechos de cancelación) no son exigibles."},
  {"id":249,"q":"Para un contrato de mejoras del hogar de una piscina, las reglas de pago inicial y avance son:","opts":["Idénticas a todos los HIC","Sujetas a límites de cronograma legales específicos","Sin regular","Establecidas por el prestamista"],"re":"Los contratos de piscinas tienen sus propias disposiciones legales de cronograma de pagos y pago inicial."},
  {"id":250,"q":"Una orden de cambio en un contrato de precio fijo debe estar:","opts":["Verbal","Por escrito, firmada, indicando el alcance, el precio y el impacto en el tiempo","Ignorada","Presentada ante el estado"],"re":"Las órdenes de cambio por escrito y firmadas evitan disputas al documentar el nuevo alcance, costo y cronograma."},
  {"id":251,"q":"La 'razón rápida' (prueba ácida) se diferencia de la razón corriente porque excluye:","opts":["El efectivo","El inventario","Las cuentas por cobrar","Las cuentas por pagar"],"re":"La razón rápida elimina el inventario para evaluar la liquidez inmediata."},
  {"id":252,"q":"Una razón de deuda a capital (debt-to-equity) alta generalmente indica:","opts":["Bajo riesgo","Mayor dependencia de dinero prestado","Más efectivo","Menores gastos generales"],"re":"Una razón de deuda a capital por encima de un rango saludable indica mayor apalancamiento y riesgo."},
  {"id":253,"q":"La depreciación lineal de un activo de $30,000 con una vida útil de 10 años y sin valor de rescate es:","opts":["$1,000/año","$3,000/año","$6,000/año","$30,000/año"],"re":"$30,000 ÷ 10 años = $3,000 por año."},
  {"id":254,"q":"La capacidad de afianzamiento de un contratista está más estrechamente vinculada a su:","opts":["Número de camiones","Capital de trabajo y patrimonio neto","Presupuesto de publicidad","Número de permisos"],"re":"Las afianzadoras determinan la capacidad de afianzamiento en gran medida a partir del capital de trabajo y el patrimonio neto."},
  {"id":255,"q":"El 'costo laboral total' (labor burden) se refiere a:","opts":["Solo el salario base","Los impuestos sobre la nómina, la compensación al trabajador y las prestaciones que se agregan al salario","Solo el tiempo extra","Los materiales"],"re":"El costo laboral total es el costo adicional de los impuestos, WC y prestaciones que se agregan al salario base."},
  {"id":256,"q":"Una línea de 'contingencia' en un estimado está destinada a cubrir:","opts":["La ganancia","Los costos imprevistos y el riesgo","El mercadeo","El salario del propietario"],"re":"La contingencia protege el estimado contra lo desconocido y el riesgo."},
  {"id":257,"q":"A menudo se exige a los grandes contratistas de construcción que usen para fines fiscales:","opts":["Solo la base de efectivo","Devengo / porcentaje de avance","Ningún método","Siempre contrato terminado"],"re":"Por encima de los umbrales del IRS, los contratistas normalmente deben usar el devengo y el porcentaje de avance."},
  {"id":258,"q":"El 'costeo por trabajo' (job costing) significa:","opts":["Un total para todos los trabajos","Rastrear la mano de obra, los materiales y los gastos generales por cada proyecto individual","Solo rastrear los impuestos","Estimar anualmente"],"re":"El costeo por trabajo asigna los costos directos y distribuidos a cada proyecto para medir la rentabilidad."},
  {"id":259,"q":"La retención (retainage) retenida a un subcontratista se registra mejor como:","opts":["Un gasto inmediato","Una cuenta por pagar liberada al finalizar","Un ingreso","Un retiro del propietario"],"re":"La retención adeudada a un subcontratista es un pasivo (cuenta por pagar) hasta que se libera al finalizar."},
  {"id":260,"q":"Si los gastos generales son de $120,000 y el margen bruto es del 30%, las ventas necesarias solo para cubrir los gastos generales son:","opts":["$120,000","$300,000","$400,000","$36,000"],"re":"$120,000 ÷ 0.30 = $400,000 en ventas para cubrir los gastos generales con un margen del 30%."},
  {"id":261,"q":"Un contratista LLC de California debe tener un seguro de responsabilidad civil de al menos:","opts":["$50,000","$100,000 con $1,000,000 de agregado (aumentando con personal adicional, hasta $5M)","$25,000","Ninguno"],"re":"Los licenciatarios LLC deben mantener un seguro de responsabilidad civil ($1M de agregado, aumentando con el personal hasta $5M) más la fianza del trabajador."},
  {"id":262,"q":"Un contratista LLC de California también debe presentar una fianza por separado en beneficio de:","opts":["El propietario","Los empleados/trabajadores ($100,000)","Solo los proveedores","El prestamista"],"re":"Las LLC deben presentar una fianza de $100,000 que protege a los empleados y trabajadores, separada de la fianza del contratista de $25,000."},
  {"id":263,"q":"California exige que los solicitantes de licencia de contratista presenten:","opts":["Un diploma universitario","Huellas dactilares (Live Scan) para una verificación de antecedentes","Una tarjeta sindical","Una licencia federal"],"re":"Los solicitantes deben presentar huellas dactilares mediante Live Scan para la revisión de antecedentes penales."},
  {"id":264,"q":"Para calificar para una C-20 (o la mayoría de las clasificaciones), un solicitante debe demostrar:","opts":["Ninguna experiencia","Al menos 4 años de experiencia a nivel de oficial (o equivalente)","Siempre 10 años","Solo un examen aprobado"],"re":"Los solicitantes generalmente necesitan 4 años de experiencia calificada a nivel de oficial dentro de los últimos 10."},
  {"id":265,"q":"California exige que los contratistas completen educación continua para renovar:","opts":["Sí, 30 horas","No — no hay un requisito general de educación continua para la renovación de la licencia de contratista","Solo para la C-20","Solo para la B general"],"re":"California no impone educación continua general para la renovación de la licencia de contratista."},
  {"id":266,"q":"En un proyecto público FEDERAL, los subcontratistas/proveedores no pagados están protegidos por:","opts":["La Ley de Gravámenes de Mecánicos de California","La fianza de pago de la Ley Miller (Miller Act)","El Título 24","La fianza de la CSLB"],"re":"La Ley Miller federal exige fianzas de pago que protegen a los subcontratistas/proveedores en proyectos federales."},
  {"id":267,"q":"Una fianza de garantía (surety bond) se diferencia de un seguro porque, después de pagar un reclamo, la afianzadora:","opts":["Absorbe la pérdida","Busca el reembolso del contratista (principal)","Cancela la licencia","Le paga al propietario para siempre"],"re":"Una fianza es una garantía de tres partes; la afianzadora puede recuperar del principal lo que paga."},
  {"id":268,"q":"En una fianza de garantía, las tres partes son el principal, el obligante (obligee) y el(la):","opts":["Prestamista","Afianzadora","Arquitecto","Inspector"],"re":"La afianzadora garantiza la obligación del principal con el obligante."},
  {"id":269,"q":"Una fianza de oferta (bid bond) normalmente se emite por qué porción de la oferta?","opts":["1%","Aproximadamente 10%","50%","100%"],"re":"Las fianzas de oferta son comúnmente alrededor del 10% del monto de la oferta."},
  {"id":270,"q":"Un proveedor de materiales que preserva sus derechos de gravamen debe entregar un aviso preliminar dentro de los 20 días de:","opts":["La finalización de la entrega","La primera entrega de materiales al sitio","La demanda","El registro del gravamen"],"re":"El plazo de 20 días corre desde el primer suministro de materiales al proyecto."},
  {"id":271,"q":"¿Qué certificación de la EPA debe tener un solicitante de la C-20 para manejar refrigerantes?","opts":["Solo Tipo I","Una certificación aplicable de la Sección 608 de la EPA (a menudo Universal)","OSHA 30","Ninguna"],"re":"El manejo de refrigerantes requiere la certificación EPA 608; la Universal cubre todos los tipos de sistemas."},
  {"id":272,"q":"Un ático o un espacio de acceso (crawlspace) durante el servicio de HVAC puede calificar como un:","opts":["Espacio público","Espacio confinado que requiere una evaluación de riesgos","Andamio","Zanja"],"re":"Las áreas de acceso restringido como los áticos/espacios de acceso pueden ser espacios confinados que requieren evaluación."},
  {"id":273,"q":"Antes de dar servicio a un equipo HVAC energizado, el técnico debe:","opts":["Trabajarlo con corriente","Aplicar bloqueo/etiquetado (lockout/tagout) para controlar la energía peligrosa","Retirar las protecciones","Omitir el EPP"],"re":"El LOTO desenergiza y asegura el equipo para evitar un arranque inesperado durante el servicio."},
  {"id":274,"q":"Una escalera recta (no autoportante) debe colocarse en una proporción de base a altura de aproximadamente:","opts":["1:1","1:4","1:8","1:20"],"re":"La regla 4:1: la base se separa 1 pie por cada 4 pies de altura de trabajo."},
  {"id":275,"q":"El resumen anual del Formulario 300A de Cal/OSHA debe exhibirse desde:","opts":["1 de enero al 1 de marzo","1 de febrero al 30 de abril","1 de julio al 1 de agosto","Todo el año"],"re":"El resumen 300A se exhibe del 1 de febrero al 30 de abril de cada año."},
  {"id":276,"q":"Los procedimientos de calor alto bajo la norma de calor de Cal/OSHA generalmente se aplican a partir de:","opts":["80°F","85°F","95°F","110°F"],"re":"Los procedimientos de calor alto (observación adicional, recordatorios) entran en vigor a los 95°F para industrias específicas."},
  {"id":277,"q":"Bajo la norma de calor, la sombra para descansar debe estar disponible cuando la temperatura alcanza:","opts":["70°F","80°F","100°F","Nunca"],"re":"Se debe proporcionar acceso a la sombra cuando la temperatura supera los 80°F."},
  {"id":278,"q":"La protección/conservación auditiva generalmente se requiere cuando el ruido alcanza un promedio de 8 horas de:","opts":["65 dB","85 dB","105 dB","130 dB"],"re":"Un programa de conservación auditiva se activa con un TWA de 8 horas de 85 dB."},
  {"id":279,"q":"Cortar/esmerilar mampostería que genera polvo implica la norma de Cal/OSHA para:","opts":["Plomo","Sílice cristalina respirable","Solo asbesto","Ruido"],"re":"El polvo del concreto/mampostería activa la norma de sílice cristalina respirable."},
  {"id":280,"q":"Reportar una amputación o una hospitalización como paciente internado relacionada con el trabajo a Cal/OSHA se requiere dentro de:","opts":["8 horas","24 horas","72 horas","1 semana"],"re":"Los resultados graves — muertes, amputaciones, hospitalización como paciente internado — se reportan dentro de 8 horas."},
  {"id":281,"q":"El incumplimiento de un contratista de comenzar sustancialmente el trabajo después de tomar un depósito puede ser:","opts":["Permitido","Una violación legal (abandono) sujeta a medidas disciplinarias","Una orden de cambio","Un gravamen"],"re":"Tomar un depósito y luego no comenzar/proseguir con diligencia es un abandono sancionable."},
  {"id":282,"q":"Una 'advertencia de gravamen de mecánicos' en un HIC le informa al propietario que:","opts":["El precio puede cambiar","Los subcontratistas/proveedores no pagados podrían gravar la vivienda incluso si el propietario pagó al contratista","Los permisos son opcionales","La fianza es nula"],"re":"Advierte que los subcontratistas/proveedores no pagados pueden gravar la propiedad a pesar de que el propietario haya pagado al contratista principal."},
  {"id":283,"q":"Un contratista que desvía fondos pagados para un proyecto específico a otros usos, perjudicando el proyecto, puede enfrentar:","opts":["Ningún problema","Medidas disciplinarias por desvío de fondos","Un crédito fiscal","Un bono"],"re":"Desviar fondos del proyecto (de modo que el trabajo se vea afectado) es una causal legal para medidas disciplinarias."},
  {"id":284,"q":"Un conjunto de documentos 'como construido' (as-built) refleja:","opts":["La oferta original","El trabajo tal como se construyó realmente, incluidos los cambios","La garantía","El gravamen"],"re":"Los documentos as-built documentan la condición final construida con todos los cambios de campo."},
  {"id":285,"q":"La oferta de un contratista generalmente se considera un(a):","opts":["Contrato vinculante","Oferta que se convierte en contrato al ser aceptada","Garantía","Gravamen"],"re":"Una oferta es una propuesta; la aceptación por parte del propietario forma el contrato."},
  {"id":286,"q":"La 'finalización' para fines de los plazos de gravamen puede activarse por la finalización real o por:","opts":["La fecha de la oferta","El cese de la mano de obra durante un período legal continuo, o la aceptación/ocupación","La emisión del permiso","La primera entrega"],"re":"La finalización también puede considerarse al momento de la aceptación, la ocupación/uso o un cese continuo de la mano de obra."},
  {"id":287,"q":"Un profesional del diseño (p. ej., un arquitecto) que no recibe pago puede, antes de la construcción, usar un(a):","opts":["Solo un gravamen de mecánicos","Gravamen del profesional del diseño bajo condiciones específicas","Solo un aviso de suspensión (stop notice)","Una fianza de oferta"],"re":"Los profesionales del diseño no pagados tienen un recurso legal limitado de gravamen del profesional del diseño."},
  {"id":288,"q":"Para disputar un gravamen registrado, un propietario puede obligar al reclamante a actuar mediante:","opts":["Ignorarlo","Exigir al reclamante que presente una demanda (o lo libere) dentro de un período reducido","Pagar el doble","Presentar un permiso"],"re":"Un propietario puede entregar una demanda que obligue al reclamante a hacer cumplir o liberar el gravamen en un plazo reducido."},
  {"id":289,"q":"Un requisito de 'fuerza laboral capacitada y entrenada' (skilled and trained workforce) en ciertas obras públicas exige:","opts":["Solo mano de obra sindicalizada","Un porcentaje de las horas de trabajo realizado por oficiales capacitados (a menudo graduados de aprendizaje)","Ningún aprendiz","Solo el postor más bajo"],"re":"Exige porcentajes establecidos de horas realizadas por oficiales capacitados, muchos formados en aprendizaje."},
  {"id":290,"q":"Una fianza de pago generalmente se requiere en los contratos de obra pública de California superiores a:","opts":["$1,000","$5,000","$25,000","$1,000,000"],"re":"Las fianzas de pago de obra pública generalmente se requieren cuando el contrato supera los $25,000."},
  {"id":291,"q":"Pagar a un trabajador una tarifa por día que, dividida entre las horas, cae por debajo del salario mínimo es:","opts":["Permitido","Una violación salarial","Está bien si se acuerda","Solo un problema para el tiempo extra"],"re":"Un pago efectivo por debajo del salario mínimo por las horas trabajadas es una violación, independientemente de la estructura de pago."},
  {"id":292,"q":"En el 7.° día laboral consecutivo, las horas POR ENCIMA de 8 se pagan a:","opts":["Tiempo normal","1.5×","2×","Sin prima"],"re":"Más allá de 8 horas en el 7.° día consecutivo, el pago es a tiempo doble."},
  {"id":293,"q":"Clasificar erróneamente a los empleados para evitar la compensación al trabajador puede conllevar:","opts":["Nada","Órdenes de suspensión, penalizaciones y posibles cargos penales","Un reembolso","Una mejora de licencia"],"re":"Evitar el WC mediante una clasificación errónea puede conllevar órdenes de suspensión, fuertes penalizaciones y exposición penal."},
  {"id":294,"q":"Si el costo de los materiales es de $2,400 y aplica un margen (markup) del 35%, el precio es:","opts":["$3,000","$3,240","$3,360","$3,692"],"re":"$2,400 × 1.35 = $3,240."},
  {"id":295,"q":"Un margen de ganancia del 20% en un trabajo de $50,000 significa una ganancia de:","opts":["$5,000","$10,000","$12,500","$20,000"],"re":"20% de $50,000 = $10,000 de ganancia."},
  {"id":296,"q":"La publicidad de un contratista que omite el número de licencia es:","opts":["Está bien","Una violación de la ley de licencias","Requerida por los prestamistas","Solo un problema en línea"],"re":"Los contratistas con licencia deben mostrar su número de licencia en toda la publicidad."},
  {"id":297,"q":"Un solicitante que tiene la experiencia pero no puede aprobar el examen:","opts":["Obtiene la licencia de todos modos","No puede obtener la licencia hasta aprobar los exámenes requeridos","Puede comprar la licencia","Está exento"],"re":"Se requieren tanto la experiencia calificada como aprobar los exámenes de leyes y del oficio para obtener la licencia."},
  {"id":298,"q":"Las modificaciones orales a un contrato con una cláusula de integración son:","opts":["Siempre vinculantes","A menudo no exigibles; los cambios deben hacerse por escrito","Requeridas","Ilegales"],"re":"Con una cláusula de integración, confíe en los cambios escritos y firmados en lugar de las promesas orales."},
  {"id":299,"q":"Un contratista que cumple sustancialmente pero deja elementos menores de la lista de pendientes (punch list) generalmente tiene derecho a:","opts":["Nada","El precio del contrato menos el costo de completar los elementos menores","Pago doble","Solo un gravamen"],"re":"El cumplimiento sustancial permite recuperar el precio menos el costo de corregir los elementos menores restantes."},
  {"id":300,"q":"La base del cumplimiento de Cal/OSHA para cualquier contratista es un(a) funcional:","opts":["Fianza","Programa de Prevención de Lesiones y Enfermedades (IIPP)","Plan de mercadeo","Registro de gravámenes"],"re":"Un IIPP funcional y por escrito es la piedra angular del cumplimiento de Cal/OSHA."},
  {"id":301,"q":"Desviar fondos recibidos para un proyecto de construcción específico hacia otro uso, perjudicando ese proyecto, es una infracción bajo el B&P Code:","opts":["§7068","§7107","§7159","§7200"],"re":"El §7107 establece que la desviación de fondos del proyecto es causa de acción disciplinaria."},
  {"id":302,"q":"El apartarse intencionalmente de las normas aceptadas del oficio o de los planos/especificaciones, causando perjuicio, es sancionable bajo:","opts":["§7109","§7114","§7120","§7058.5"],"re":"El §7109 cubre el apartamiento intencional de los planos/especificaciones o de las normas aceptadas del oficio."},
  {"id":303,"q":"Ayudar o instigar a una persona sin licencia a evadir la ley de licencias infringe:","opts":["§7107","§7110","§7114","§7123"],"re":"El §7114 prohíbe colaborar con la actividad sin licencia."},
  {"id":304,"q":"La violación intencional de las leyes de construcción, seguridad, laborales o salariales por parte de un contratista es causa de acción disciplinaria bajo:","opts":["§7110","§7116","§7159","§7065"],"re":"El §7110 cubre la violación intencional de las leyes de construcción/seguridad/laborales/compensación."},
  {"id":305,"q":"El fraude o la tergiversación intencional para obtener una licencia o al ejecutar trabajo es sancionable bajo:","opts":["§7068","§7116","§7120","§7200"],"re":"El §7116 aborda el fraude o la tergiversación intencional."},
  {"id":306,"q":"El incumplimiento intencional de pagar por materiales o servicios prestados, teniendo la capacidad de hacerlo, es causa de acción disciplinaria bajo:","opts":["§7120","§7107","§7114","§7058"],"re":"El §7120 cubre el incumplimiento intencional de pagar por materiales o servicios."},
  {"id":307,"q":"Abandonar un proyecto sin excusa legal, o no completarlo por el precio contratado, es sancionable bajo:","opts":["§7113","§7065","§7159","§7137"],"re":"El §7113 aborda el no completar el trabajo por el precio acordado / el abandono."},
  {"id":308,"q":"Una acción disciplinaria de la CSLB por un defecto patente (evidente) generalmente debe iniciarse dentro de cuántos años del acto?","opts":["1","2","4","10"],"re":"Para actos patentes, el plazo de prescripción para la acción de la CSLB es generalmente de 4 años."},
  {"id":309,"q":"Para un defecto latente (oculto), el plazo de prescripción de la CSLB para actuar es generalmente:","opts":["4 años","10 años","Sin límite","1 año"],"re":"La acción disciplinaria por defecto latente generalmente debe iniciarse dentro de 10 años."},
  {"id":310,"q":"Después de que se revoca una licencia, el contratista generalmente no puede solicitar la reinstalación o una nueva licencia durante al menos:","opts":["30 días","1 año","5 años","Permanentemente"],"re":"Un titular con licencia revocada generalmente no puede volver a solicitarla durante al menos un año (más en algunos casos)."},
  {"id":311,"q":"Una 'citación' de la CSLB puede imponer una orden de corrección y una multa civil sin:","opts":["Ningún aviso","Una audiencia completa bajo la Administrative Procedure Act","Ninguna infracción","El conocimiento del contratista"],"re":"Una citación resuelve asuntos con corrección/multa sin llegar a una audiencia disciplinaria completa (el contratista puede apelar)."},
  {"id":312,"q":"La estructura de remedios al consumidor de la CSLB de California notablemente NO incluye:","opts":["La fianza del contratista","Arbitraje obligatorio/voluntario","Un fondo estatal de recuperación (como en algunos otros estados)","Acción ante un tribunal civil"],"re":"California no tiene un fondo de recuperación para contratistas; los consumidores recurren a la fianza, el arbitraje o el tribunal."},
  {"id":313,"q":"El arbitraje obligatorio de una queja por parte de la CSLB generalmente aplica a disputas de hasta:","opts":["$1,000","$15,000","$50,000","$100,000"],"re":"El arbitraje obligatorio de la CSLB generalmente cubre disputas de hasta $15,000; el voluntario hasta $50,000."},
  {"id":314,"q":"Un procedimiento disciplinario formal ante la CSLB se rige por la:","opts":["Penal Code","Administrative Procedure Act","Vehicle Code","UCC"],"re":"Las audiencias disciplinarias de la CSLB siguen la Administrative Procedure Act."},
  {"id":315,"q":"Una condena por un delito sustancialmente relacionado con las cualificaciones/deberes de un contratista puede ser causa de:","opts":["Una bonificación","Denegación o acción disciplinaria sobre una licencia","Renovación automática","Nada"],"re":"Las condenas sustancialmente relacionadas pueden sustentar la denegación o la acción disciplinaria sobre la licencia."},
  {"id":316,"q":"Para imponer una sanción, la CSLB generalmente debe probar las infracciones mediante:","opts":["Más allá de toda duda razonable","Evidencia clara y convincente (con certeza razonable)","Un volado","Nada"],"re":"La acción disciplinaria profesional normalmente requiere evidencia clara y convincente."},
  {"id":317,"q":"Si se paga una reclamación contra la fianza de un contratista, el contratista generalmente debe:","opts":["No hacer nada","Reinstalar/reemplazar la fianza para mantener la licencia activa","Entregar la licencia","Duplicar la fianza para siempre"],"re":"Tras un pago de la fianza, el contratista debe restablecer el afianzamiento para mantener una licencia activa."},
  {"id":318,"q":"Todos los nuevos solicitantes de licencia deben aprobar el examen de asbesto a libro abierto de la CSLB bajo el B&P Code:","opts":["§7058.5","§7068","§7159","§7110"],"re":"El §7058.5 exige el examen de asbesto a libro abierto antes de la licencia (no certifica para el trabajo con asbesto)."},
  {"id":319,"q":"Para realizar trabajo relacionado con asbesto por encima del umbral regulatorio, un contratista debe poseer adicionalmente:","opts":["Solo una C-20","Una certificación de asbesto (registro con Cal/OSHA DOSH) y aprobar un examen de certificación","Nada adicional","Una licencia de bienes raíces"],"re":"El trabajo relacionado con asbesto requiere una certificación de asbesto por separado y registro con Cal/OSHA."},
  {"id":320,"q":"La clasificación independiente de la CSLB específicamente para la remoción de asbesto es:","opts":["C-20","C-22","C-36","B"],"re":"La C-22 es la clasificación de Remoción de Asbesto (Asbestos Abatement); es independiente."},
  {"id":321,"q":"El registro de asbesto con Cal/OSHA generalmente se requiere cuando el trabajo involucra más de:","opts":["10 sq ft / linear ft","100 sq ft o 100 linear ft de material que contiene asbesto","1,000 sq ft","Cualquier cantidad"],"re":"El registro se requiere por encima de 100 sq ft / 100 linear ft de ACM."},
  {"id":322,"q":"Antes de ciertas demoliciones/renovaciones, las reglas federales NESHAP exigen notificar al distrito de aire con al menos:","opts":["1 día","10 días hábiles de anticipación","30 días después","Nunca"],"re":"NESHAP generalmente requiere una notificación con 10 días hábiles de anticipación para demoliciones/renovaciones reguladas."},
  {"id":323,"q":"El trabajo de construcción relacionado con plomo (p. ej., perturbar pintura con plomo) en California requiere que los trabajadores estén:","opts":["Sin restricciones","Certificados/capacitados para trabajo relacionado con plomo (CDPH) con los controles adecuados","Solo C-22","Certificados EPA 608"],"re":"El trabajo con plomo requiere certificación/capacitación de plomo del CDPH y controles de ingeniería."},
  {"id":324,"q":"La remoción de sustancias peligrosas (certificación HAZ) está disponible solo para contratistas que primero poseen:","opts":["Cualquier licencia C","Clasificaciones especificadas (A, B, C-36, C-12, C-57, etc.) más un examen de certificación","Ninguna licencia","Solo una C-20"],"re":"La certificación HAZ se superpone a clasificaciones base especificadas y requiere aprobar un examen de certificación."},
  {"id":325,"q":"En un proyecto privado, un 'aviso afianzado de suspensión de pago' (bonded stop payment notice) de un subcontratista:","opts":["No tiene efecto","Obliga al prestamista a retener fondos (con prioridad sobre un aviso no afianzado)","Reemplaza el gravamen","Es ilegal"],"re":"Un bonded stop payment notice puede obligar a un prestamista de construcción a retener fondos y tiene prioridad."},
  {"id":326,"q":"La prioridad de un gravamen de constructor (mechanics lien) generalmente 'se retrotrae' a:","opts":["La fecha de registro del gravamen","La fecha en que el trabajo comenzó por primera vez en el proyecto","La fecha de finalización","La fecha del permiso"],"re":"La prioridad del gravamen normalmente se retrotrae al inicio de la obra de mejora."},
  {"id":327,"q":"Un jornalero que personalmente realizó el trabajo generalmente:","opts":["Debe entregar un aviso de 20 días como los proveedores","Tiene derechos de gravamen sin entregar un aviso preliminar","No tiene derechos de gravamen","Debe registrar dentro de 10 días"],"re":"Las reclamaciones salariales de los jornaleros generalmente están exentas del requisito de aviso preliminar."},
  {"id":328,"q":"En un proyecto FEDERAL, un reclamante de segundo nivel bajo el Miller Act debe dar aviso al contratista principal dentro de:","opts":["20 días","90 días del último suministro","1 año","Sin aviso"],"re":"Los reclamantes de segundo nivel del Miller Act deben notificar al contratista principal dentro de 90 días del último suministro de mano de obra/materiales."},
  {"id":329,"q":"Una demanda sobre una fianza de pago del Miller Act generalmente debe presentarse dentro de:","opts":["90 días","6 meses","1 año del último suministro","4 años"],"re":"La demanda sobre una fianza de pago del Miller Act debe entablarse dentro de un año del último suministro."},
  {"id":330,"q":"El gravamen de un profesional del diseño (para arquitectos/ingenieros) generalmente aplica:","opts":["Después de la finalización","Antes de que comience la construcción, por servicios previos a la construcción no pagados, bajo ciertas condiciones","Solo en obras públicas","Nunca"],"re":"Brinda recuperación limitada por servicios de diseño previos a la construcción no pagados bajo condiciones establecidas."},
  {"id":331,"q":"Un préstamo de construcción de un prestamista registrado ANTES de que comience el trabajo generalmente tiene prioridad sobre:","opts":["Nada","Gravámenes de constructor posteriores (porque los gravámenes se retrotraen al inicio)","El propietario","Los impuestos sobre la propiedad"],"re":"Una escritura de fideicomiso registrada antes de cualquier trabajo tiene prioridad porque los gravámenes se retrotraen al inicio."},
  {"id":332,"q":"Un reclamante que sobrevalora un gravamen de mala fe puede:","opts":["Recuperar más","Perder el gravamen y enfrentar responsabilidad","Obtener una bonificación","No enfrentar nada"],"re":"Un gravamen exagerado intencionalmente puede ser nulo y exponer al reclamante a daños y perjuicios."},
  {"id":333,"q":"Operar con una licencia suspendida es:","opts":["Permitido brevemente","Tratado como contratación sin licencia (una infracción)","Permitido para trabajos existentes","Solo un asunto de papeleo"],"re":"Contratar mientras se está suspendido se trata como actividad sin licencia."},
  {"id":334,"q":"Si un calificador (qualifier) se va y no es reemplazado dentro del plazo legal, la licencia queda:","opts":["Sin afectar","Suspendida automáticamente","Mejorada","Transferida"],"re":"No reemplazar al calificador a tiempo resulta en la suspensión."},
  {"id":335,"q":"Un contratista que cobra sustancialmente de más en comparación con un precio razonable ('precio excesivo') puede enfrentar:","opts":["Nada","Acción disciplinaria donde el estatuto lo define como infracción (p. ej., precios abusivos en desastres)","Una bonificación","Un crédito fiscal"],"re":"El cobro excesivo en contextos definidos (p. ej., emergencias declaradas) puede ser una infracción."},
  {"id":336,"q":"Durante un estado de emergencia declarado, aumentar precios de muchos bienes/servicios por encima de un porcentaje establecido es:","opts":["Permitido","Precio abusivo prohibido (comúnmente limitado cerca del 10%)","Fomentado","Solo un asunto civil"],"re":"El Penal Code §396 limita la mayoría de los aumentos de precios (comúnmente ~10%) durante emergencias declaradas."},
  {"id":337,"q":"Un contratista debe reportar a la CSLB una condena por delito grave o por cierto delito menor porque:","opts":["Es opcional","La no divulgación puede ser en sí misma una infracción","La CSLB nunca verifica","Solo importan los DUI"],"re":"Los titulares de licencia deben divulgar ciertas condenas; el ocultamiento es sancionable de forma independiente."},
  {"id":338,"q":"Un contratista que perturba superficies pintadas en una vivienda anterior a 1978 debe asumir la presencia de:","opts":["Solo asbesto","Pintura a base de plomo (hasta que se demuestre lo contrario con pruebas)","Nada","Solo moho"],"re":"Se presume que las viviendas anteriores a 1978 contienen pintura a base de plomo en ausencia de pruebas."},
  {"id":339,"q":"Disponer indebidamente de residuos peligrosos (p. ej., refrigerante, solventes) puede resultar en:","opts":["Ningún problema","Multas ambientales y responsabilidad","Un crédito fiscal","Una bonificación de la CSLB"],"re":"La disposición ilegal de residuos peligrosos acarrea sanciones ambientales y responsabilidad."},
  {"id":340,"q":"Ventilar la mayoría de los refrigerantes HFC/HCFC a la atmósfera durante el servicio es:","opts":["Permitido","Prohibido bajo la EPA Section 608","Requerido","Solo un asunto estatal"],"re":"La EPA §608 prohíbe ventilar a sabiendas refrigerantes regulados."},
  {"id":341,"q":"Si los pasivos de un contratista exceden los activos, el negocio tiene:","opts":["Capital positivo","Patrimonio neto negativo (riesgo de insolvencia)","Alta liquidez","Sin gastos generales"],"re":"Pasivos mayores que activos significa capital negativo y posible insolvencia."},
  {"id":342,"q":"Un fiador (surety) que evalúa el afianzamiento examinará más de cerca las 'tres C':","opts":["Cash, cars, contracts (efectivo, autos, contratos)","Capital, capacity, character (capital, capacidad, carácter)","Cost, color, county (costo, color, condado)","Credit, clients, codes (crédito, clientes, códigos)"],"re":"Los fiadores ponderan capital, capacidad y carácter (capital, capacity, character)."},
  {"id":343,"q":"Subfacturar (underbilling) en un trabajo por porcentaje de avance significa que el contratista ha:","opts":["Facturado más de lo ganado","Facturado menos que el trabajo completado (un activo circulante)","Cobrado de más","No tiene trabajo restante"],"re":"La subfacturación (costos en exceso de las facturaciones) se registra como un activo circulante."},
  {"id":344,"q":"Un empleador que toma represalias contra un trabajador por presentar una reclamación salarial puede enfrentar:","opts":["Nada","Sanciones y responsabilidad por reinstalación/pago retroactivo","Un crédito fiscal","Una bonificación"],"re":"Las represalias por quejas salariales protegidas son ilícitas y acarrean sanciones."},
  {"id":345,"q":"Cal/OSHA puede emitir una 'Orden de Prohibición de Uso' (Order Prohibiting Use) para:","opts":["Cancelar una licencia","Prohibir el uso de equipo/área peligrosa hasta que se corrija un peligro","Fijar salarios","Aprobar un permiso"],"re":"Una OPU detiene el uso de equipo/áreas de trabajo que representan un peligro inminente hasta que se corrija."},
  {"id":346,"q":"Un 'peligro inminente' bajo Cal/OSHA le permite a la agencia:","opts":["No hacer nada","Ordenar la corrección inmediata o cerrar la operación","Esperar un año","Emitir una bonificación"],"re":"Los peligros inminentes justifican órdenes de corrección inmediata o el cierre."},
  {"id":347,"q":"Una cláusula de 'renuncia a la subrogación' (waiver of subrogation) significa que una aseguradora acuerda:","opts":["Duplicar la cobertura","No perseguir a la otra parte después de pagar una reclamación","Cancelar la póliza","Pagar gravámenes"],"re":"Renuncia al derecho de la aseguradora de recuperar de la otra parte nombrada."},
  {"id":348,"q":"Una cláusula de 'indemnización' requiere que una parte:","opts":["Pague impuestos","Cubra/defienda a la otra contra pérdidas o reclamaciones especificadas","Compre materiales","Tramite permisos"],"re":"La indemnización traslada la responsabilidad por ciertas pérdidas/reclamaciones a la parte indemnizante."},
  {"id":349,"q":"En California, una cláusula de indemnización que traslada la responsabilidad por la ÚNICA negligencia del indemnizado generalmente es:","opts":["Totalmente exigible","Nula/inexigible en contratos de construcción","Requerida","Deducible de impuestos"],"re":"Las cláusulas que indemnizan a una parte por su propia única negligencia son nulas en los contratos de construcción."},
  {"id":350,"q":"Un 'Aviso de Finalización' (Notice of Completion) en un proyecto de obras públicas afecta:","opts":["Los salarios","Los plazos para los avisos de suspensión de pago y las reclamaciones de fianza","La oferta","El permiso"],"re":"En obras públicas, los eventos de finalización acortan los plazos para los avisos de suspensión de pago y las reclamaciones de fianza."},
  {"id":351,"q":"Certificar falsamente el cumplimiento de la fuerza laboral capacitada y entrenada (skilled-and-trained-workforce) en obras públicas es:","opts":["Menor","Una infracción grave con sanciones","Fomentado","Permitido por debajo de $25k"],"re":"Las certificaciones falsas de cumplimiento exponen al contratista a sanciones y responsabilidad."},
  {"id":352,"q":"El registro DIR para obras públicas generalmente debe:","opts":["Hacerse una sola vez para siempre","Renovarse (en un ciclo establecido) y estar vigente para ofertar/trabajar","Ser opcional","Hacerse después del trabajo"],"re":"Los contratistas deben mantener vigente el registro DIR para ofertar y ejecutar obras públicas."},
  {"id":353,"q":"Un contratista que anuncia una especialidad para la que NO tiene licencia comete:","opts":["Mercadeo inteligente","Una infracción de la ley de licencias","Solo un delito federal","Nada"],"re":"Anunciar trabajo fuera de su clasificación/sin licencia es una infracción."},
  {"id":354,"q":"Una pregunta de clasificación de contratista de 'mejoras del hogar': los reemplazos de HVAC en viviendas existentes típicamente se realizan bajo:","opts":["Ninguna licencia","Una C-20 (con las reglas de HIC aplicando al contrato)","Una licencia de bienes raíces","Una C-22"],"re":"El trabajo de HVAC usa la C-20; las reglas del contrato de mejoras del hogar rigen el acuerdo con el consumidor."},
  {"id":355,"q":"Un contratista no puede hacer cumplir una cláusula contractual que requiera que el consumidor:","opts":["Pague el precio","Renuncie al derecho a un jurado o a protecciones legales sin una divulgación clara y visible","Proporcione acceso","Elija colores"],"re":"Las renuncias ocultas a derechos importantes son inexigibles; la divulgación debe ser clara y visible."},
  {"id":356,"q":"Un problema de 'liquidez' se aborda mejor con:","opts":["Comprar más equipo","Mejorar el flujo de efectivo (facturación, cobranza, términos de crédito)","Contratar a más gente","Bajar los precios"],"re":"La liquidez mejora mediante facturación/cobranza más rápida y crédito gestionado, no mediante más gasto."},
  {"id":357,"q":"Una retención por cobrar del 10% sobre un contrato de $200,000 equivale a:","opts":["$2,000","$10,000","$20,000","$40,000"],"re":"El 10% de $200,000 = $20,000 retenidos como retención."},
  {"id":358,"q":"Un empleado lesionado en el trabajo debe primero:","opts":["Demandar al empleador","Reportarlo y presentar una reclamación de compensación de trabajadores","Renunciar","Llamar a la CSLB"],"re":"Las lesiones laborales se gestionan a través del sistema de compensación de trabajadores, comenzando con un reporte pronto y una reclamación."},
  {"id":359,"q":"La compensación de trabajadores generalmente proporciona a los empleados:","opts":["Daños punitivos","Atención médica y beneficios de reemplazo de salario independientemente de la culpa","Un nuevo empleo","Acciones"],"re":"La compensación de trabajadores es sin culpa: tratamiento médico y reemplazo parcial del salario."},
  {"id":360,"q":"Las sanciones de Cal/OSHA suelen ser más altas para infracciones que son:","opts":["Accidentales","Reincidentes, graves o intencionales","Menores y de primera vez","Solo autorreportadas"],"re":"Las infracciones reincidentes, graves e intencionales conllevan sanciones más severas."},
  {"id":361,"q":"La fianza de $25,000 del contratista protege principalmente a:","opts":["El contratista","Propietarios de viviendas, ciertos empleados y otros especificados, contra infracciones","El prestamista","El IRS"],"re":"La fianza cubre reclamaciones legales de consumidores, empleados (salarios) y otros específicos."},
  {"id":362,"q":"Una reclamación salarial de un empleado contra la fianza del contratista generalmente está limitada a:","opts":["Ilimitada","Una porción legal de la fianza","Siempre la fianza completa","Nada"],"re":"Las reclamaciones salariales/de beneficios de empleados pueden alcanzar una porción definida de la fianza."},
  {"id":363,"q":"Un contrato 'en blanco' firmado por un consumidor (con términos completados después) es:","opts":["Una buena práctica","Prohibido — los términos importantes deben estar presentes al firmar","Requerido","Solo para obras públicas"],"re":"Los consumidores no deben firmar contratos con términos importantes dejados en blanco."},
  {"id":364,"q":"El incumplimiento de un contratista de incluir un aviso requerido en un HIC puede hacer que el contrato sea:","opts":["Más fuerte","Susceptible de impugnación/inexigible en parte","Libre de impuestos","Público"],"re":"La omisión de avisos obligatorios del HIC puede hacer que el contrato sea impugnable o parcialmente inexigible."},
  {"id":365,"q":"El derecho de un consumidor a cancelar un contrato de solicitud a domicilio (home-solicitation) corre por:","opts":["1 día","3 días hábiles desde la firma/recepción del aviso","30 días","Nunca"],"re":"El derecho a cancelar es de 3 días hábiles desde la firma y la recepción del aviso."},
  {"id":366,"q":"Para ciertos adultos mayores y personas con discapacidad, el período de cancelación puede ser:","opts":["Más corto","Extendido más allá de 3 días en situaciones definidas","Eliminado","Basado en impuestos"],"re":"Algunos estatutos otorgan a adultos mayores/personas con discapacidad especificados derechos de cancelación más largos."},
  {"id":367,"q":"Una oferta 'responsiva' (responsive) en obras públicas es aquella que:","opts":["Es la más baja","Cumple con los requisitos/especificaciones de la oferta","Es de un local","No está firmada"],"re":"La responsividad significa que la oferta cumple con los requisitos de la solicitud."},
  {"id":368,"q":"Un oferente 'responsable' (responsible) es aquel que:","opts":["Oferta lo más bajo","Tiene la capacidad, integridad y confiabilidad para ejecutar","Es una corporación","No presenta fianza"],"re":"La responsabilidad se refiere a la capacidad y confiabilidad del oferente para ejecutar."},
  {"id":369,"q":"Para actuar en nombre de una licencia, un 'empleado de buena fe' (bona fide employee, para fines de RME) debe ser:","opts":["Un testaferro","Empleado de forma permanente con deberes de supervisión reales","Un contratista de medio tiempo","Solo un propietario"],"re":"Un RME debe ser una persona genuina, empleada de forma permanente, que ejerza supervisión real."},
  {"id":370,"q":"Un arreglo fraudulento donde el calificador no ejerce control real es:","opts":["Permitido","Una infracción (licencia disponible para uso indebido)","Común y legal","Exento de impuestos"],"re":"Un calificador solo de nombre, sin control real, viola la ley de licencias."},
  {"id":371,"q":"La evaluación médica requerida para un respirador debe ocurrir:","opts":["Después de un año de uso","Antes de que el empleado pase la prueba de ajuste y lo use","Solo si se solicita","Nunca"],"re":"La autorización médica precede a la prueba de ajuste y al uso del respirador."},
  {"id":372,"q":"Una infracción 'general' de Cal/OSHA (vs. grave) es aquella que:","opts":["Podría causar la muerte","Tiene una relación directa/inmediata con la seguridad pero sin probabilidad de lesión grave","Es intencional","Es penal"],"re":"Una infracción general se relaciona con la seguridad/salud sin una probabilidad sustancial de daño grave."},
  {"id":373,"q":"Un ejemplo de costo de gasto general 'fijo' es:","opts":["Materiales del trabajo","Renta mensual de la oficina","Subcontratista por trabajo","Combustible por trabajo"],"re":"La renta de la oficina es un gasto general fijo independientemente del volumen de trabajo."},
  {"id":374,"q":"Un ejemplo de costo 'variable' es:","opts":["Prima de seguro","Materiales que aumentan con el volumen de trabajo","Salario de oficina","Cuota de licencia"],"re":"Los materiales varían directamente con la producción/el volumen de trabajo."},
  {"id":375,"q":"Un empleador debe proporcionar un lugar de trabajo libre de peligros reconocidos bajo la:","opts":["UCC","Obligación de deber general (Cal/OSHA)","Código fiscal","Ley de gravámenes"],"re":"El deber general requiere un lugar de trabajo libre de peligros graves reconocidos."},
  {"id":376,"q":"Una póliza de responsabilidad 'paraguas' (umbrella) proporciona:","opts":["Compensación de trabajadores","Límites en exceso por encima de las pólizas primarias de GL/auto","Una fianza","Seguro de salud"],"re":"La cobertura paraguas agrega límites en exceso por encima de las pólizas de responsabilidad subyacentes."},
  {"id":377,"q":"La cobertura de 'operaciones completadas' (completed operations) protege contra reclamaciones que surgen:","opts":["Solo durante el trabajo","Después de que el trabajo está terminado, derivadas de ese trabajo completado","Solo de autos","Solo de robo"],"re":"Las operaciones completadas cubren la responsabilidad derivada del trabajo después de que se completa."},
  {"id":378,"q":"Un contrato de 'costo más un precio máximo garantizado (GMP)':","opts":["No tiene tope","Reembolsa costos más honorarios pero limita el total","Es de suma alzada","Paga por unidad"],"re":"Un costo más GMP reembolsa el costo real más honorarios, pero no por encima del tope."},
  {"id":379,"q":"Un contrato de 'precio unitario' (unit price) es mejor cuando:","opts":["Las cantidades son desconocidas pero las tarifas unitarias están establecidas","Todo está fijo","No existen mediciones","Solo para viviendas"],"re":"Los contratos de precio unitario se adaptan a trabajos donde las cantidades varían pero las tarifas por unidad están acordadas."},
  {"id":380,"q":"Las agencias públicas a menudo requieren, antes de la adjudicación, que un oferente presente una:","opts":["Gravamen","Fianza de oferta o garantía de oferta","Declaración de impuestos","Permiso"],"re":"Una fianza/garantía de oferta acompaña a la oferta para garantizar que el oferente contratará."},
  {"id":381,"q":"Un contratista condenado por un delito puede demostrar 'rehabilitación' ante la CSLB mediante:","opts":["Ignorarlo","Evidencia de tiempo transcurrido, restitución y conducta modificada","Pagar la fianza","Volver a anunciar"],"re":"La CSLB pondera la evidencia de rehabilitación: tiempo, restitución, cumplimiento y conducta."},
  {"id":382,"q":"Una persona 'cualificada' (qualified, vs. competente) bajo Cal/OSHA usualmente tiene:","opts":["Ninguna capacitación","Título/certificado reconocido o conocimiento extenso para resolver problemas en la materia","Solo una licencia","Una fianza"],"re":"Una persona cualificada tiene experiencia reconocida (título/certificado/experiencia) para la materia específica."},
  {"id":383,"q":"Para preservar un aviso de suspensión de pago en un trabajo privado, el reclamante generalmente también debe haber entregado:","opts":["Un gravamen","Un aviso preliminar de 20 días válido","Una fianza","Un permiso"],"re":"Un aviso preliminar oportuno sustenta los derechos del aviso de suspensión de pago y del gravamen para reclamantes no directos."},
  {"id":384,"q":"Un gravamen de constructor generalmente NO está disponible contra:","opts":["Una vivienda privada","Propiedad pública (use un aviso de suspensión de pago / fianza en su lugar)","Un edificio comercial","Una remodelación"],"re":"La propiedad pública no puede gravarse; los remedios son la fianza de pago y el aviso de suspensión de pago."},
  {"id":385,"q":"Una 'rescisión' (rescission) de un contrato busca:","opts":["Agregar alcance","Deshacer el contrato y restaurar a las partes a sus posiciones previas","Aumentar el precio","Extender el plazo"],"re":"La rescisión cancela el contrato y busca devolver a las partes al estado anterior (status quo ante)."},
  {"id":386,"q":"El 'cumplimiento específico' (specific performance) es un remedio que:","opts":["Solo paga dinero","Obliga a una parte a ejecutar el contrato según lo acordado","Cancela el trato","Agrega una fianza"],"re":"El cumplimiento específico ordena la ejecución real cuando los daños monetarios son insuficientes."},
  {"id":387,"q":"El estado de pérdidas y ganancias de un contratista para el año muestra ingresos $800k, COGS $560k, gastos generales $180k. La ganancia neta es:","opts":["$60,000","$240,000","$120,000","$20,000"],"re":"$800k − $560k = $240k bruto; $240k − $180k de gastos generales = $60k neto."},
  {"id":388,"q":"Un empleador debe llevar un registro de las horas trabajadas para empleados no exentos porque:","opts":["Es opcional","La ley salarial requiere registros de tiempo precisos","Solo para impuestos","La CSLB lo requiere"],"re":"Se requieren registros de tiempo precisos para cumplir con la ley salarial y de horas."},
  {"id":389,"q":"Pagar a un trabajador por 'tarifa por pieza' (piece rate) aún requiere:","opts":["Sin mínimo","Al menos el salario mínimo por todas las horas y pago por separado del tiempo de descanso/recuperación","Solo el pago por pieza","Sin descansos"],"re":"Los trabajadores por tarifa por pieza aún deben ganar al menos el salario mínimo y se les debe pagar por los períodos de descanso/recuperación."},
  {"id":390,"q":"Un sistema de protección contra caídas en alturas incluye:","opts":["Solo señales","Barandillas, sistema personal de detención de caídas o redes de seguridad según corresponda","Solo guantes","Nada por debajo de 30 ft"],"re":"Los sistemas aceptables incluyen barandillas, PFAS o redes según la tarea."},
  {"id":391,"q":"Una licencia emitida a una corporación está vinculada a:","opts":["Cualquier directivo","Esa entidad corporativa específica y su calificador","El prestamista","La ciudad"],"re":"La licencia pertenece a la entidad específica; no puede ser usada por una entidad diferente."},
  {"id":392,"q":"Vender o transferir el número de licencia de un contratista a otro es:","opts":["Permitido con una cuota","Prohibido — las licencias no son transferibles","Común","Fomentado"],"re":"Las licencias de contratista no son transferibles ni vendibles."},
  {"id":393,"q":"A los aprendices en obras públicas se les debe pagar:","opts":["Nada","La tarifa de salario prevaleciente de aprendiz aplicable a su nivel","Siempre la tarifa de oficial","Solo el salario mínimo"],"re":"Los aprendices reciben la tarifa de aprendiz prevaleciente correspondiente a su progresión."},
  {"id":394,"q":"El 'margen bruto %' de un contratista en un trabajo que costó $7,000 y se vendió por $10,000 es:","opts":["20%","30%","43%","70%"],"re":"Margen = (10,000 − 7,000)/10,000 = 30%."},
  {"id":395,"q":"Una propuesta firmada que contiene todos los términos esenciales y es aceptada se convierte en:","opts":["Un gravamen","Un contrato vinculante","Un permiso","Una fianza"],"re":"La aceptación de una oferta completa forma un contrato vinculante."},
  {"id":396,"q":"El mejor primer paso cuando un material desconocido puede contener asbesto es:","opts":["Demolerlo","Detenerse y hacer que sea muestreado/analizado por una parte cualificada","Quemarlo","Pintar encima"],"re":"El ACM sospechoso debe analizarse antes de perturbarlo; asuma que es peligroso hasta que se descarte."},
  {"id":397,"q":"Una 'liberación de gravamen' (release of lien) debe obtenerse de los subcontratistas/proveedores para:","opts":["Aumentar el precio","Confirmar que han sido pagados y que no gravarán la propiedad","Cancelar el permiso","Evitar impuestos"],"re":"Las liberaciones de gravamen documentan el pago y protegen al propietario/contratista principal de gravámenes posteriores."},
  {"id":398,"q":"Un contratista que deja vencer su licencia y sigue trabajando está:","opts":["Bien","Operando sin licencia y expuesto al §7031 y a acción disciplinaria","Protegido","Exento"],"re":"Trabajar con una licencia vencida es actividad sin licencia con exposición al §7031 y a acción disciplinaria."},
  {"id":399,"q":"Un IIPP debe incluir todo lo siguiente EXCEPTO:","opts":["Identificación y corrección de peligros","Capacitación y comunicación","Una persona responsable","Un presupuesto de mercadeo"],"re":"Los elementos del IIPP incluyen responsabilidad, identificación/corrección de peligros, capacitación y comunicación — no el mercadeo."},
  {"id":400,"q":"La mejor manera de evitar acciones disciplinarias de la CSLB es:","opts":["Evitar contratos","Cumplir con la ley de licencias, terminar el trabajo y comunicar/resolver problemas con prontitud","Nunca tener una fianza","Trabajar sin licencia"],"re":"El cumplimiento, completar el trabajo y la pronta resolución de problemas previenen la mayoría de los problemas disciplinarios."},
  {"id":401,"q":"Todos los siguientes pueden calificar la licencia de un contratista EXCEPTO un(a):","opts":["RMO (propietario)","RME (empleado)","Solicitante propietario único","Amigo sin licencia y sin relación con la empresa"],"re":"Solo un RMO calificado, un RME, o un propietario único que califique pueden calificar una licencia, no una persona sin licencia y sin relación con la empresa."},
  {"id":402,"q":"¿Cuál es la MENOS probable que requiera una licencia de la CSLB?","opts":["Una instalación de HVAC de $5,000","Una reparación de $1,200 con permiso","Una reparación de $300 de un solo oficio, sin permiso, sin empleados","Una remodelación de $50,000"],"re":"El trabajo por debajo del límite, de un solo oficio, sin permiso ni empleados, es el menos probable que requiera una licencia."},
  {"id":403,"q":"Una empresa con $50,000 de activos circulantes y $20,000 de pasivos circulantes tiene una razón circulante de:","opts":["0.4","1.5","2.5","5.0"],"re":"50,000 ÷ 20,000 = 2.5."},
  {"id":404,"q":"Si quiere un margen bruto del 25% en un trabajo que cuesta $9,000, debe cobrar:","opts":["$11,250","$12,000","$11,000","$10,800"],"re":"Precio = costo ÷ (1 − margen) = 9,000 ÷ 0.75 = $12,000."},
  {"id":405,"q":"Un empleado trabaja 10 horas el lunes. Las horas extra adeudadas a 1.5× son:","opts":["0","1","2","10"],"re":"Las horas 9 y 10 (más de 8 al día) se pagan a 1.5×; eso son 2 horas extra."},
  {"id":406,"q":"Un empleado trabaja 13 horas en un día. Las horas a tiempo doble adeudadas son:","opts":["0","1","4","5"],"re":"Más de 12 horas activa el 2×; solo la hora 13 es tiempo doble (las horas 9 a 12 son a 1.5×)."},
  {"id":407,"q":"Sin un Aviso de Terminación (Notice of Completion) registrado, ¿cuánto tiempo tienen TODOS los reclamantes después de la terminación para registrar un gravamen?","opts":["30 días","60 días","90 días","6 meses"],"re":"Sin un NOC, todos tienen 90 días después de la terminación."},
  {"id":408,"q":"Un aviso preliminar entregado 35 días después de suministrar materiales por primera vez protege los derechos de gravamen:","opts":["Por todos los montos","Solo por los materiales suministrados dentro de los 20 días previos al aviso y en adelante","Por nada","Por el doble del monto"],"re":"Un aviso preliminar tardío protege solo los montos dentro de los 20 días previos a la entrega y en adelante."},
  {"id":409,"q":"Se firma un contrato de mejoras al hogar por $40,000. El pago inicial máximo legal es:","opts":["$4,000","$1,000","$10,000","$2,000"],"re":"El menor entre $1,000 o el 10% ($4,000) = $1,000."},
  {"id":410,"q":"En un trabajo de mejoras al hogar de HVAC de $6,000, el pago inicial máximo es:","opts":["$600","$1,000","$1,200","$3,000"],"re":"El 10% de $6,000 = $600, que es menos que $1,000, así que $600 es el tope."},
  {"id":411,"q":"El salario prevaleciente (prevailing wage) en una reparación municipal de $900 es:","opts":["Requerido","No requerido (por debajo del límite de $1,000)","Doble","Opcional"],"re":"Por debajo del límite de $1,000, el salario prevaleciente generalmente no aplica."},
  {"id":412,"q":"Todos los siguientes son programas/elementos requeridos por Cal/OSHA EXCEPTO:","opts":["IIPP por escrito","Prevención de enfermedades por calor (al aire libre)","Comunicación de Peligros / acceso a SDS","Un plan de reparto de utilidades"],"re":"El reparto de utilidades no es un requisito de seguridad; los demás son mandatos de Cal/OSHA."},
  {"id":413,"q":"Un contratista cambia de propietario único a una LLC. La acción correcta es:","opts":["Conservar la licencia anterior","Solicitar una nueva licencia para la LLC","Solo avisar al banco","No hacer nada"],"re":"Una nueva entidad legal requiere su propia licencia; la anterior no puede transferirse."},
  {"id":414,"q":"Un contratista LLC debe mantener TANTO una fianza de contratista de $25,000 como un(a):","opts":["Fianza de $5,000","Fianza de trabajador de $100,000 más seguro de responsabilidad civil","Depósito de $1,000","Nada adicional"],"re":"Las LLC necesitan la fianza de $25k, una fianza de trabajador de $100k, y seguro de responsabilidad civil."},
  {"id":415,"q":"¿Cuál NO es un activo circulante?","opts":["Efectivo","Cuentas por cobrar","Una camioneta de trabajo de 10 años","Inventario"],"re":"Una camioneta de larga duración es un activo fijo, no un activo circulante."},
  {"id":416,"q":"¿Cuál es un pasivo a largo plazo?","opts":["Las cuentas por pagar de este mes","Un préstamo de equipo a 6 años","Salarios que vencen el viernes","Una factura a 30 días"],"re":"Un préstamo de varios años es un pasivo a largo plazo."},
  {"id":417,"q":"Un empleado gana un bono no discrecional de $200 en una semana de 40 horas. Para las horas extra de esa semana, el bono:","opts":["Se ignora","Debe incluirse en la tarifa regular","Se duplica","Se grava dos veces"],"re":"Los bonos no discrecionales elevan la tarifa regular usada para calcular las horas extra."},
  {"id":418,"q":"Un trabajador renuncia sin aviso el martes. El pago final vence:","opts":["De inmediato","Dentro de 72 horas","El siguiente día de pago","En 30 días"],"re":"Renuncia sin aviso: los salarios finales dentro de 72 horas."},
  {"id":419,"q":"Un contratista quiere que un gravamen registrado se elimine rápidamente para limpiar el título. El propietario puede:","opts":["Esperar a que venza","Registrar una fianza de liberación de gravamen (125% del gravamen)","Demandar al prestamista","Cancelar el permiso"],"re":"Una fianza de liberación del 125% sustituye a la propiedad, limpiando el título."},
  {"id":420,"q":"Una orden de cambio debe ejecutarse:","opts":["Verbalmente, después","Por escrito y firmada ANTES de que proceda el trabajo modificado","Después del trabajo","Solo si supera los $10,000"],"re":"Obtenga las órdenes de cambio por escrito y firmadas antes de hacer el trabajo adicional."},
  {"id":421,"q":"En un trabajo de obras públicas, el contratista debe registrar aprendices y presentar la nómina certificada. No hacerlo arriesga:","opts":["Nada","Multas, pagos retenidos e inhabilitación","Un bono","Pago más rápido"],"re":"El incumplimiento arriesga multas, fondos retenidos e inhabilitación."},
  {"id":422,"q":"A 96°F al aire libre, los deberes del empleador por calor incluyen todo EXCEPTO:","opts":["Agua","Sombra","Procedimientos de calor alto","Emitir opciones sobre acciones"],"re":"Las opciones sobre acciones no son un deber del estándar de calor; el agua, la sombra y los procedimientos de calor alto sí lo son."},
  {"id":423,"q":"Anunciarse como contratista con licencia sin tener una licencia vigente es:","opts":["Permitido","Una infracción","Solo un problema en línea","Recomendado"],"re":"Presentarse como con licencia sin tener una licencia válida es una infracción."},
  {"id":424,"q":"Para presentar el examen de oficio para C-20, el solicitante generalmente necesita aproximadamente cuántos años de experiencia a nivel oficial (journey-level)?","opts":["1","2","4","8"],"re":"Cuatro años de experiencia calificada dentro de los últimos 10 es el requisito general."},
  {"id":425,"q":"La recuperación de gastos generales en una cotización se logra mediante:","opts":["Ignorar los gastos generales","Agregar un margen/asignación a los costos del trabajo para cubrir gastos generales y utilidad","Bajar el precio","Omitir el seguro"],"re":"Las cotizaciones deben incluir un margen que recupere los gastos generales y la utilidad objetivo."},
  {"id":426,"q":"Un subcontratista con licencia que usted contrata y que dirige su propia cuadrilla es, para su nómina:","opts":["Su empleado","No es su empleado","Un aprendiz","Un socio"],"re":"Un subcontratista genuino con licencia y con sus propios trabajadores no es empleado de su nómina."},
  {"id":427,"q":"¿Cuál es VERDADERA sobre un gravamen de constructor (mechanics lien) en un proyecto de escuela pública?","opts":["Se adhiere a la escuela","No está disponible; use un aviso de retención de pago (stop payment notice)/fianza de pago","Se duplica","No necesita aviso"],"re":"La propiedad pública no puede gravarse; use el aviso de retención de pago y la fianza de pago."},
  {"id":428,"q":"Un contrato que carece de objeto lícito (p. ej., trabajo requerido sin licencia) es:","opts":["Exigible","Nulo","Solo anulable","Expreso"],"re":"Un contrato con objeto ilícito es nulo."},
  {"id":429,"q":"¿Cuál NO es requisito para un contrato válido?","opts":["Consentimiento mutuo","Contraprestación","Objeto lícito","Una garantía de utilidad"],"re":"No se necesita una 'garantía de utilidad'; el consentimiento, la contraprestación, la capacidad y el objeto lícito sí lo son."},
  {"id":430,"q":"Se presenta una cotización con un error matemático de $5,000 en contra del contratista (demasiado baja). El contratista puede:","opts":["Nunca retirarla","Buscar retirarla/rescindirla de inmediato si el error es sustancial y cumple las condiciones","Duplicar el precio después de la adjudicación","Ignorarlo"],"re":"Un error clerical genuino y sustancial en la cotización, planteado de inmediato, puede permitir la rescisión."},
  {"id":431,"q":"Antes de entrar a un ático para dar servicio a un equipo, el técnico debe considerar:","opts":["Nada","Peligros de calor, espacio confinado y caídas/apoyo","Solo el precio","Solo la fianza"],"re":"Los áticos representan peligros de calor, espacio confinado y caídas que deben evaluarse primero."},
  {"id":432,"q":"El número de licencia del contratista debe aparecer en todos los siguientes EXCEPTO:","opts":["Tarjetas de presentación/anuncios","Contratos","Propuestas de cotización","Una tarjeta de cumpleaños personal"],"re":"El número va en la publicidad, los contratos y las propuestas, no en artículos personales no relacionados."},
  {"id":433,"q":"Un capital de trabajo negativo significa que los pasivos circulantes:","opts":["Son cero","Superan a los activos circulantes (riesgo de liquidez)","Igualan a los activos","Están exentos de impuestos"],"re":"Capital de trabajo negativo = los pasivos circulantes superan a los activos circulantes."},
  {"id":434,"q":"¿Qué trabajador es más claramente un EMPLEADO?","opts":["Un subcontratista con licencia y cuadrilla propia","Un ayudante por hora a quien usted dirige y le proporciona las herramientas","Un proveedor de materiales","Una firma separada que usted subcontrata"],"re":"Un trabajador por hora, dirigido y que usa sus herramientas es un empleado."},
  {"id":435,"q":"Una fianza de cumplimiento y una fianza de pago juntas protegen:","opts":["Solo al contratista","La terminación del proyecto Y el pago a subcontratistas/proveedores","Solo al prestamista","Solo a la ciudad"],"re":"La fianza de cumplimiento asegura la terminación; la de pago asegura a los subcontratistas/proveedores."},
  {"id":436,"q":"Un consumidor firma en su hogar tras una propuesta de venta a domicilio. Puede cancelar dentro de:","opts":["24 horas","3 días hábiles","30 días","Nunca"],"re":"Las ventas por solicitud a domicilio conllevan un derecho de cancelación de 3 días hábiles."},
  {"id":437,"q":"La nómina certificada existe principalmente para:","opts":["Establecer la cotización","Comprobar el cumplimiento del salario prevaleciente y del programa de aprendizaje","Reducir impuestos","Evitar permisos"],"re":"La nómina certificada documenta el cumplimiento del salario prevaleciente y del programa de aprendizaje."},
  {"id":438,"q":"El documento MÁS importante para el cumplimiento de Cal/OSHA en un contratista pequeño es el:","opts":["Fianza","IIPP por escrito","Hoja de cotización","Registro de gravámenes"],"re":"El IIPP por escrito es la base del cumplimiento de Cal/OSHA."},
  {"id":439,"q":"Un contratista sancionado que busca una nueva licencia tras una revocación generalmente debe esperar al menos:","opts":["1 semana","1 año","Nunca se permite","Siempre 10 años"],"re":"La nueva solicitud tras una revocación generalmente está prohibida durante al menos un año."},
  {"id":440,"q":"La cotización de un contratista debe incluir una contingencia para:","opts":["Aumentar los impuestos","Amortiguar costos/riesgos imprevistos","Bajar el precio","Omitir el seguro"],"re":"Una contingencia amortigua frente a lo desconocido y el riesgo."},
  {"id":441,"q":"Un empleador no proporciona un descanso de comida libre de deberes en un turno de 6 horas. Al empleado se le adeuda:","opts":["Nada","Una hora de pago de prima","Una disculpa por escrito","Tiempo doble"],"re":"Un periodo de comida omitido adeuda una hora de prima a la tarifa regular."},
  {"id":442,"q":"Un subcontratista que entregó un aviso preliminar válido y no recibió pago debe, a continuación:","opts":["Dejar el oficio","Registrar un gravamen de constructor dentro del plazo (y/o entregar un aviso de retención de pago)","Llamar a la policía","No hacer nada"],"re":"Con un aviso preliminar válido, registre un gravamen a tiempo y/o entregue un aviso de retención de pago."},
  {"id":443,"q":"Si un contrato escrito y una promesa verbal paralela están en conflicto (con cláusula de integración), generalmente:","opts":["Gana la verbal","El contrato escrito prevalece","Ambos son nulos","El gravamen prevalece"],"re":"Con la integración, el documento escrito prevalece sobre los términos verbales previos."},
  {"id":444,"q":"Para cotizar un proyecto de HVAC de escuela de $2,000,000, un contratista C-20 debe, entre otras cosas:","opts":["Nada especial","Estar registrado con el DIR, pagar el salario prevaleciente y cumplir las reglas de aprendizaje/fuerza laboral calificada","Solo tener una fianza","Evitar la nómina certificada"],"re":"Las obras públicas requieren registro con el DIR, salario prevaleciente, nómina certificada y reglas de fuerza laboral."},
  {"id":445,"q":"Un trabajador debe ser reportado a Cal/OSHA dentro de 8 horas por:","opts":["Una cortada menor","Una muerte, amputación u hospitalización como paciente internado","Una llegada tarde","Un problema de estacionamiento"],"re":"Los resultados graves (muerte, amputación, hospitalización) requieren reporte dentro de 8 horas."},
  {"id":446,"q":"¿Qué acción NO requiere notificar a la CSLB?","opts":["Cambio de domicilio comercial","Desvinculación del calificador","Cambio de entidad comercial","Comprar una nueva camioneta de trabajo"],"re":"Comprar una camioneta no es un cambio reportable a la CSLB; los cambios de domicilio, calificador y entidad sí lo son."},
  {"id":447,"q":"Un 'análisis de punto de equilibrio' ayuda a un contratista a determinar:","opts":["La fianza","Las ventas necesarias para cubrir todos los costos","La tarifa del permiso","El monto del gravamen"],"re":"El punto de equilibrio muestra el volumen de ventas donde los ingresos igualan al costo total."},
  {"id":448,"q":"El pago de nómina en efectivo 'por debajo de la mesa' viola más directamente:","opts":["El código de construcción","La ley de impuestos sobre la nómina y la ley laboral (y arriesga cargos por fraude)","La ley de gravámenes","El Title 24"],"re":"El pago no registrado evade los impuestos sobre la nómina y la ley laboral y puede ser delito."},
  {"id":449,"q":"¿Cuál es la secuencia correcta de gravamen (sin NOC)?","opts":["Gravamen → aviso preliminar → demanda","Aviso preliminar de 20 días → registrar el gravamen dentro de 90 días → demanda de ejecución dentro de 90 días","Demanda → gravamen → aviso","Aviso → demanda → gravamen"],"re":"Entregue el aviso preliminar, registre el gravamen dentro de 90 días, luego demande dentro de 90 días del registro."},
  {"id":450,"q":"Un contratista que toma un depósito y nunca comienza el trabajo puede ser responsable por:","opts":["Nada","Abandono/desvío: sanción más reembolso/daños","Un bono","Un crédito fiscal"],"re":"Tomar dinero y abandonar es sancionable y expone al contratista a reembolsos/daños."},
  {"id":451,"q":"Una 'orden de cambio' en un contrato de obras públicas generalmente debe ser:","opts":["Verbal","Por escrito y aprobada según el contrato/los procedimientos de la agencia","Ignorada","Oculta"],"re":"Los contratos públicos requieren órdenes de cambio por escrito y aprobadas siguiendo los procedimientos de la agencia."},
  {"id":452,"q":"El EPP debe ser proporcionado por el empleador:","opts":["A costo del empleado","Sin costo para el empleado cuando se requiere","Solo en obras públicas","Nunca"],"re":"El EPP requerido lo proporciona el empleador sin costo para los trabajadores."},
  {"id":453,"q":"Un 'individuo calificador' que posee al menos el 10% de la corporación es típicamente un(a):","opts":["RME","RMO","Aprendiz","Tenedor de la fianza"],"re":"Un calificador propietario (10%+) es el RMO; un calificador empleado es el RME."},
  {"id":454,"q":"El patrimonio neto de una empresa equivale a:","opts":["Efectivo disponible","Activos totales menos pasivos totales","Ingresos anuales","Margen"],"re":"Patrimonio neto (capital) = activos − pasivos."},
  {"id":455,"q":"¿Cuál es un impuesto sobre la nómina pagado por el empleador (no retenido al trabajador)?","opts":["Impuesto sobre la renta del empleado","Impuesto de desempleo FUTA/SUI","SDI","La parte de FICA del trabajador"],"re":"Los impuestos de desempleo los paga el empleador; el impuesto sobre la renta, el SDI y la parte de FICA del empleado se retienen."},
  {"id":456,"q":"Una 'renuncia y liberación condicional sobre el pago final' surte efecto:","opts":["Al firmar","Cuando el pago final realmente se acredita","Nunca","Después de 90 días"],"re":"Las renuncias finales condicionales surten efecto solo una vez que se recibe/acredita el pago final."},
  {"id":457,"q":"Una cláusula de daños liquidados de $500/día por un retraso de 10 días resulta en:","opts":["$500","$5,000","$50","$10,000"],"re":"$500 × 10 = $5,000."},
  {"id":458,"q":"En obras públicas que superan los $25,000, el contratista generalmente debe proporcionar un(a):","opts":["Gravamen","Fianza de pago","Formulario del Title 24","Plan de marketing"],"re":"Las fianzas de pago en obras públicas son requeridas cuando el contrato supera los $25,000."},
  {"id":459,"q":"La regla de escalera 4:1 significa que para una altura de trabajo de 16 pies, la base se separa:","opts":["1 pie","2 pies","4 pies","8 pies"],"re":"16 ÷ 4 = 4 pies de separación de la base."},
  {"id":460,"q":"La ventana para reclamar la fianza de un contratista generalmente está limitada; los reclamos deben presentarse dentro de:","opts":["Sin límite","Un periodo legal (comúnmente dentro de unos años del acto)","10 días","Para siempre"],"re":"Los reclamos de fianza están sujetos a plazos legales; preséntelos de inmediato."},
  {"id":461,"q":"Si los gastos generales son el 18% de las ventas y la utilidad neta objetivo es el 8%, el margen total sobre el costo del trabajo debe cubrir:","opts":["8%","18%","26% (gastos generales + utilidad) de las ventas","0%"],"re":"El precio debe cubrir los gastos generales (18%) más la utilidad (8%) = 26% de las ventas por encima del costo directo."},
  {"id":462,"q":"Un empleado no exento trabaja 45 horas en una semana (9/día × 5). Las horas extra de esa semana suman:","opts":["0","5","8","10"],"re":"Cada día tiene 1 hora extra (la 9.ª); 5 días = 5 horas extra a 1.5×."},
  {"id":463,"q":"Un proveedor de materiales sin contrato directo con el propietario preserva sus derechos de gravamen principalmente mediante:","opts":["Registrar primero","Entregar a tiempo un aviso preliminar de 20 días","Llamar al propietario","Presentar impuestos"],"re":"El aviso preliminar de 20 días preserva los derechos de gravamen de un proveedor remoto."},
  {"id":464,"q":"Una cláusula de contrato que exige que todas las disputas sean decididas por un tercero neutral con un laudo vinculante es:","opts":["Mediación","Arbitraje vinculante","Estoppel","Un gravamen"],"re":"Eso describe el arbitraje vinculante."},
  {"id":465,"q":"Un contratista paga de menos los salarios prevalecientes y luego 'completa' la diferencia tras una auditoría. Aun así enfrenta:","opts":["Nada","Multas y posible inhabilitación","Un reembolso","Un bono"],"re":"La restitución no borra las multas ni la exposición a la inhabilitación por el pago insuficiente."},
  {"id":466,"q":"¿Cuál es la MEJOR respuesta ante la sospecha de asbesto durante la remoción de una caldera?","opts":["Removerlo rápido","Detenerse, aislar y hacer que lo pruebe una parte calificada","Mojarlo y embolsarlo usted mismo","Ignorarlo"],"re":"Detenga el trabajo y pruebe el material sospechoso de contener asbesto (ACM) antes de perturbarlo."},
  {"id":467,"q":"Ayudar a una persona sin licencia a contratar y luego tomar una comisión es:","opts":["Un negocio inteligente","Una infracción de la ley de licencias (ayudar a actividad sin licencia)","Legal por debajo de $5,000","Recomendado"],"re":"Ayudar a contratar sin licencia a cambio de una comisión viola la ley de licencias."},
  {"id":468,"q":"El costeo de trabajos revela que un proyecto perdió dinero. El siguiente paso MÁS útil es:","opts":["Ocultarlo","Analizar el estimado frente a los costos reales para corregir cotizaciones futuras","Dejar de costear los trabajos","Aumentar la fianza"],"re":"Compare los costos estimados frente a los reales para corregir la estimación y evitar pérdidas repetidas."},
  {"id":469,"q":"¿Cuál es VERDADERA sobre la compensación de trabajadores para un propietario único sin empleados?","opts":["Siempre requerida","Puede presentar una exención (sin empleados)","Es ilegal omitirla","La paga el cliente"],"re":"Un propietario único sin empleados puede certificar una exención de WC."},
  {"id":470,"q":"Un endoso de asegurado adicional en la póliza de un subcontratista típicamente beneficia al:","opts":["Solo al subcontratista","Contratista general/propietario nombrado como asegurado adicional","Solo al prestamista","A la ciudad"],"re":"Extiende la cobertura del subcontratista al GC/propietario como asegurado adicional."},
  {"id":471,"q":"Un contratista quiere limitar su responsabilidad por retrasos causados por el clima. La mejor herramienta es una:","opts":["Gravamen","Cláusula de fuerza mayor / retraso excusable","Fianza","Permiso"],"re":"Una cláusula de fuerza mayor/retraso excusable aborda los retrasos fuera del control del contratista."},
  {"id":472,"q":"La cotización más baja no es conforme (le falta una fianza requerida). La agencia debe:","opts":["Adjudicarla de todos modos","Tratarla como no responsiva y puede rechazarla","Duplicarla","Ignorar las reglas"],"re":"Una cotización a la que le faltan elementos requeridos es no responsiva y puede rechazarse."},
  {"id":473,"q":"Un espacio confinado con una atmósfera peligrosa requiere, antes de entrar:","opts":["Nada","Pruebas atmosféricas, ventilación/controles y un permiso/programa","Solo una linterna","Una fianza"],"re":"Los espacios confinados que requieren permiso necesitan pruebas, controles y un programa de entrada."},
  {"id":474,"q":"Todos los nuevos solicitantes de licencia de la CSLB deben completar el:","opts":["Examen de asbesto a libro abierto","Certificación C-22","Examen HAZ","Curso de bienes raíces"],"re":"Todo nuevo solicitante debe aprobar el examen de asbesto a libro abierto antes de obtener la licencia."},
  {"id":475,"q":"La capacidad de fianza de un contratista MEJORARÁ más con:","opts":["Comprar camionetas a crédito","Aumentar el capital de trabajo y el patrimonio neto, y un historial limpio","Bajar los precios","Omitir el seguro"],"re":"Un mayor capital de trabajo, patrimonio neto e historial elevan la capacidad de fianza."},
  {"id":476,"q":"Un empleador que clasifica a empleados reales como 1099 para evadir impuestos/WC arriesga:","opts":["Nada","Impuestos atrasados, multas, responsabilidad de WC y posibles cargos penales","Un reembolso","Un bono"],"re":"La clasificación errónea deliberada conlleva impuestos atrasados, multas, responsabilidad de WC y posiblemente delitos."},
  {"id":477,"q":"La fianza de $25,000 del contratista está destinada a compensar el daño derivado de:","opts":["Cualquier pérdida del negocio","Infracciones específicas que afectan a consumidores, empleados y ciertos otros","Mal clima","Alzas en los precios de materiales"],"re":"La fianza cubre las infracciones legales que dañan a propietarios de vivienda, empleados y ciertos otros."},
  {"id":478,"q":"Un HIC NO debe:","opts":["Indicar el precio","Proporcionar un calendario de pagos basado en el trabajo","Exigir un pago inicial mayor al tope legal","Incluir el aviso de cancelación"],"re":"Exceder el tope legal del pago inicial está prohibido."},
  {"id":479,"q":"Un contratista en obras públicas debe mantener el registro con el DIR:","opts":["Vencido está bien","Vigente y renovado en plazo","Solo para el primer trabajo","Opcional"],"re":"El registro con el DIR debe permanecer vigente para cotizar/ejecutar obras públicas."},
  {"id":480,"q":"Un nuevo empleado debe recibir capacitación de seguridad:","opts":["Después de un año","Antes/al inicio del trabajo para sus tareas asignadas","Solo si se lesiona","Nunca"],"re":"Capacite a los trabajadores sobre los peligros antes o al comenzar el trabajo asignado."},
  {"id":481,"q":"Si el calificador de un contratista fallece, la empresa debe:","opts":["Seguir operando indefinidamente","Notificar de inmediato a la CSLB y reemplazar al calificador dentro del tiempo permitido","Ocultarlo","Vender la licencia"],"re":"Notifique a la CSLB y reemplace al calificador dentro del plazo legal para evitar la suspensión."},
  {"id":482,"q":"Un 'margen' del 20% sobre un costo de $5,000 da un precio de:","opts":["$5,200","$6,000","$6,250","$1,000"],"re":"$5,000 × 1.20 = $6,000."},
  {"id":483,"q":"Un trabajador en el 7.º día consecutivo trabaja 9 horas. El pago es:","opts":["Todo a tiempo normal","8 horas a 1.5× y la 9.ª hora a 2×","Todo a tiempo doble","Sin prima"],"re":"7.º día: las primeras 8 horas a 1.5×, más allá de 8 a 2×."},
  {"id":484,"q":"El recurso en un proyecto público FEDERAL para subcontratistas no pagados es la:","opts":["Gravamen estatal","Fianza de pago de la Miller Act","Title 24","Fianza de la CSLB"],"re":"Los proyectos federales usan la fianza de pago de la Miller Act."},
  {"id":485,"q":"Un contratista completa sustancialmente una cocina pero la puerta de un gabinete está desalineada. El propietario generalmente debe:","opts":["Nada","El precio menos el costo de corregir el detalle menor","El doble","Solo el pago inicial"],"re":"Cumplimiento sustancial: el precio menos el costo de corregir los detalles menores de la lista de pendientes."},
  {"id":486,"q":"Presentar una nómina certificada falsificada es:","opts":["Un error menor","Fraude: multas, inhabilitación y exposición penal","Estándar","Recomendado"],"re":"La nómina certificada falsificada es un fraude grave con consecuencias severas."},
  {"id":487,"q":"Para dar servicio de forma segura a un equipo energizado en la azotea, PRIMERO:","opts":["Empezar a trabajar","Desenergizar y aplicar bloqueo/etiquetado (lockout/tagout)","Quitar los protectores","Omitir el EPP"],"re":"Desenergice y aplique LOTO antes de dar servicio."},
  {"id":488,"q":"Un contratista C-20 quiere también hacer trabajo en paneles eléctricos. Debe:","opts":["Simplemente hacerlo","Tener/obtener la clasificación adecuada (p. ej., C-10) o usar un subcontratista C-10 con licencia","Omitir el permiso","Anunciarlo de todos modos"],"re":"El trabajo eléctrico necesita la clasificación C-10 o un subcontratista C-10 con licencia."},
  {"id":489,"q":"La razón rápida (quick ratio) de un contratista es 0.7. Esto sugiere:","opts":["Liquidez fuerte","Posible dificultad para cubrir deudas a corto plazo sin vender inventario","Sin riesgo","Alta utilidad"],"re":"Una razón rápida por debajo de 1 indica una liquidez ajustada a corto plazo."},
  {"id":490,"q":"Un contratista debe proporcionar un estado de cuenta de salario detallado:","opts":["Anualmente","Cada periodo de pago","Solo a solicitud","Nunca"],"re":"Un recibo de pago detallado es requerido en cada periodo de pago."},
  {"id":491,"q":"¿Cuál de estas es VERDADERA sobre los avisos preliminares?","opts":["Solo los propietarios los envían","Muchos reclamantes deben entregarlos dentro de los 20 días del primer suministro para preservar sus derechos","Reemplazan a los gravámenes","Nunca son requeridos"],"re":"Los reclamantes no directos generalmente deben entregar un aviso preliminar de 20 días."},
  {"id":492,"q":"Una cláusula 'tal como está' (as-is) en un contrato intenta:","opts":["Agregar una garantía","Limitar las garantías sobre la condición entregada","Aumentar el precio","Agregar una fianza"],"re":"'Tal como está' intenta limitar las garantías implícitas sobre la condición entregada."},
  {"id":493,"q":"En obras públicas, los aprendices deben emplearse en una proporción no menor a:","opts":["1:1","1:5 (aprendiz:oficial)","1:10","0"],"re":"Generalmente se requiere al menos 1 hora de aprendiz por cada 5 horas de oficial."},
  {"id":494,"q":"El resumen anual 300A de Cal/OSHA se publica del 1 de febrero al:","opts":["1 de marzo","30 de abril","30 de junio","31 de diciembre"],"re":"Publique el 300A del 1 de febrero al 30 de abril."},
  {"id":495,"q":"La publicidad de un contratista que afirma una clasificación que no tiene es:","opts":["Permitida","Una infracción","Inteligente","Requerida"],"re":"Anunciar una clasificación que no se tiene es una infracción de la ley de licencias."},
  {"id":496,"q":"Para fijar el precio de un trabajo para obtener una utilidad neta del 10% tras un 25% de gastos generales sobre un costo directo de $10,000, agregaría aproximadamente:","opts":["$1,000","$3,500 (gastos generales + utilidad sobre el costo)","$500","$0"],"re":"Gastos generales 25% ($2,500) + utilidad objetivo ~10% (~$1,000+) ≈ $3,500 de margen sobre el costo de $10,000 (aprox.)."},
  {"id":497,"q":"Un empleador debe reportar una nueva contratación al EDD dentro de:","opts":["20 días","60 días","90 días","1 año"],"re":"Las nuevas contrataciones se reportan al EDD dentro de 20 días."},
  {"id":498,"q":"Un gravamen registrado pero nunca ejecutado dentro de 90 días:","opts":["Permanece para siempre","Se vuelve inexigible y debe liberarse","Se duplica","Se convierte en una fianza"],"re":"Sin una demanda de ejecución a tiempo, el gravamen es inexigible y debe liberarse."},
  {"id":499,"q":"La protección más fuerte contra una disputa de pago es:","opts":["Un apretón de manos","Un contrato escrito claro con alcance, precio, calendario y términos de órdenes de cambio","Un pago inicial mayor","Una fianza más grande"],"re":"Un contrato escrito completo es la mejor defensa contra las disputas de pago."},
  {"id":500,"q":"El propósito general de la Ley de Licencias de Contratistas del Estado (Contractors State License Law) es:","opts":["Maximizar las tarifas","Proteger al público y garantizar una contratación competente y honesta","Limitar la competencia","Aumentar los impuestos"],"re":"La ley de licencias existe para proteger al público mediante una contratación competente y honesta."}
];
